INSERT INTO sub_areas (id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active)
VALUES
  ('suzhou_canglang_pavilion_sa_01', 'suzhou_canglang_pavilion', 'Mianshui Pavilion (Water-Facing Pavilion)', '面水轩', 'Mianshui Pavilion sits just north of the garden entrance and serves as the first architectural highlight visitors encounter. Facing the water on its northern side, it spans three bays with a stone terrace projecting into the pond, making it the premier spot for viewing the outer Fengxi stream and borrowed scenery. The name "Mianshui" aptly describes its defining feature of facing the water. The structure uses a flush gable roof with a low eave line, maintaining an intimate connection with the water. It stands as the garden''s overture, embodying Canglang Pavilion''s celebrated concept of water encircling the garden before one even enters.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_01.jpg', 0),
  ('suzhou_canglang_pavilion_sa_02', 'suzhou_canglang_pavilion', 'Guanyu Spot (Fish-Watching Spot)', '观鱼处', 'Guanyu Spot lies east of Mianshui Pavilion, consisting of a stone terrace and a small viewing area at the water''s edge. The open water teems with koi, evoking the ancient tale of Zhuangzi watching fish at Hao River, reflecting the garden owner''s philosophical pursuit of transcendence. The terrace is built with Lake Tai stones arranged in varied heights, with weeping willows and sweet flag planted along the shore, their reflections enhancing the serene atmosphere. Visitors gazing at the leisurely koi can share the Song literati''s spiritual resonance with "the joy of fish," making this one of the most philosophically rich viewing spots in the garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_02.jpg', 1),
  ('suzhou_canglang_pavilion_sa_03', 'suzhou_canglang_pavilion', 'Canglang Pavilion', '沧浪亭', 'Canglang Pavilion is the centerpiece of the entire garden, perched atop a stone-and-earth hill at the center, exemplifying the rare Suzhou layout of "water encircling the garden with the hill as its core." The square pavilion features a four-hipped roof with upturned eaves, radiating classical elegance. Its columns bear the famous couplet by late-Qing scholar Yu Yue: "The refreshing breeze and bright moon are beyond price; near waters and distant hills both stir the heart." The name derives from the Chu Ci verse about the Canglang waters, symbolizing the owner''s aspiration to retire from worldly affairs and preserve his integrity. From within, visitors gaze south at the hill and ancient trees, and north at the pond beyond the walls—the zenith of the garden''s borrowing-scenery philosophy.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_03.jpg', 2),
  ('suzhou_canglang_pavilion_sa_04', 'suzhou_canglang_pavilion', 'Mingdao Hall (Hall of Understanding the Way)', '明道堂', 'Mingdao Hall stands south of Canglang Pavilion and is the largest hall in the garden, spanning three bays with a deep plan and a broad front terrace. The name "Mingdao" means "to understand the Way of the former sages," dating back to Su Shunqin''s original Song-era garden and preserved through subsequent rebuilds. The interior exposes its timber frame with large, unpainted members, reflecting the austere architectural style of the Song dynasty. The spacious forecourt is planted with ancient magnolias and bamboo, creating an elegant ambiance. This was the venue where the owner gathered with literati for scholarly discourse and poetic exchange, embodying the intellectual spirit of Canglang Pavilion as a Song literati garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_04.jpg', 3),
  ('suzhou_canglang_pavilion_sa_05', 'suzhou_canglang_pavilion', 'Kanshan Tower (Mountain-Viewing Tower)', '看山楼', 'Kanshan Tower stands on a stone terrace atop the hill at the garden''s southern end, a two-story pavilion with a flush-gable roof, marking the highest point in Canglang Pavilion. Its name "Kanshan" means "viewing mountains," as ascending it reveals vistas of Tianping, Lingyan, and Lion hills to the southwest. The tower masterfully employs the "distant borrowing" technique, drawing mountains beyond the garden walls into the visual composition, creating a sense of infinite space within finite bounds. The lower level is built on a yellow-stone base, while the upper timber story spreads its eaves gracefully. From the windows, visitors see bamboo and banana leaves nearby and blue mountain silhouettes afar, capturing the idyllic serenity celebrated by Song literati.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_05.jpg', 4),
  ('suzhou_canglang_pavilion_sa_06', 'suzhou_canglang_pavilion', 'Cui Linglong (Emerald Chamber)', '翠玲珑', 'Cui Linglong is a small study tucked in a bamboo grove west of Kanshan Tower. Spanning merely one and a half bays, it is surrounded by tall bamboo on three sides, with sunlight filtering through the leaves to cast dappled shadows, creating an atmosphere of profound seclusion. The poetic name combines "cui" (emerald green bamboo) and "linglong" (exquisite and translucent). This was Su Shunqin''s reading chamber, where he depicted scenes of studying amid bamboo in his "Record of Canglang Pavilion." A winding path before the chamber is dotted with Lake Tai stones, their forms interplaying with bamboo shadows. Removed from the main tourist route, the spot is exceptionally tranquil, offering an ideal place to experience the reclusive life of a Song literati and the garden''s technique of suggesting grandeur through intimacy.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_06.jpg', 5),
  ('suzhou_canglang_pavilion_sa_07', 'suzhou_canglang_pavilion', 'Five Hundred Sages Shrine', '五百名贤祠', 'The Five Hundred Sages Shrine, located in the northwest of Canglang Pavilion, was established in the seventh year of the Daoguang reign (1827) by Tao Zhu, then Governor of Jiangsu. Its walls are inlaid with stone-carved half-length portraits of 594 Suzhou worthies spanning over two thousand years, from Ji Zha of the Spring and Autumn period to Lin Zexu of the Qing dynasty, covering politics, literature, art, and science. Each portrait is accompanied by a name and brief inscription, executed with succinct yet expressive carving. The shrine is not merely a memorial but a stone-carved chronicle of Suzhou''s cultural heritage, embodying the city''s reputation for producing exceptional talent. The architecture is austere and dignified, with grey brick and tile complementing the solemnity of the portraits.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_07.jpg', 6),
  ('suzhou_canglang_pavilion_sa_08', 'suzhou_canglang_pavilion', 'Imperial Stele Pavilion', '御碑亭', 'The Imperial Stele Pavilion is located in the west-central area of Canglang Pavilion, a small pavilion built specifically to shelter a stele inscribed by Emperor Kangxi of the Qing dynasty. The stele bears Kangxi''s own calligraphy, composed during his southern inspection tour, praising the scenery of Canglang Pavilion and the virtue of Su Shunqin. The stele is carved from bluestone with a dragon-crested top and a bixi (mythical tortoise) base, exhibiting typical Qing imperial stele characteristics. The pavilion is square with a pyramidal roof and four stone columns, open on all sides for viewing the stele. It holds significant historical and cultural value, demonstrating the garden''s sustained importance from the Song to the Qing, and represents a rare surviving example of imperial stele within Suzhou gardens.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_08.jpg', 7),
  ('suzhou_canglang_pavilion_sa_09', 'suzhou_canglang_pavilion', 'Ouhua Water Pavilion (Lotus Water Pavilion)', '藕花水榭', 'Ouhua Water Pavilion sits at the northern water''s edge of Canglang Pavilion, a classical waterside structure half-suspended over the pond. It is built facing the water, with the lower portion supported on stone columns projecting over the surface, and an upper timber structure with a flush-gable roof, open on all sides for panoramic water views. The name "Ouhua" refers to lotus flowers, which were historically planted here in abundance; in midsummer the scene of boundless green lotus leaves and crimson blooms is particularly enchanting. Beyond lotus viewing, the pavilion offers one of the best vantage points for the outer pond and borrowed scenery to the north. Even in autumn and winter, the withered lotus leaves on the water convey a melancholy beauty, embodying the Suzhou garden aesthetic of beauty in all four seasons.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_canglang_pavilion_sa_09.jpg', 8),
  ('suzhou_lingering_garden_sa_01', 'suzhou_lingering_garden', 'Ancient Trees Interlocking', '古木交柯', 'Ancient Trees Interlocking lies at the entrance area of Lingering Garden, greeting visitors as the first scenic vista upon stepping into the garden. An ancient cypress and a camellia intertwine their branches, resembling lovers leaning upon each other, hence the name "Interlocking." This scene embodies the harmonious coexistence of rugged strength and delicate beauty, reflecting the Chinese philosophical concept of yin-yang complementarity. The Ming dynasty painter Wen Zhengming once depicted similar imagery; this living scene in Lingering Garden serves as a vivid re-creation and a superb example of the garden design principle of "seeing the grand in the small."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_01.jpg', 0),
  ('suzhou_lingering_garden_sa_02', 'suzhou_lingering_garden', 'Green Shade Pavilion', '绿荫轩', 'Green Shade Pavilion sits in the central part of Lingering Garden, adjacent to Hanbi Mountain House. It is a small pavilion-style structure built against a wall and facing the water. Ancient trees before the pavilion cast dense shade; sitting here in summer, one enjoys gentle breezes and faint lotus scents—a uniquely tranquil pleasure. The name "Green Shade" highlights its environmental essence—using tree canopy to create a cooling ambiance, a classic example of Suzhou garden techniques of "borrowed and screened views." With simple furnishings and verdant views beyond the windows, a single table and chair suffice for tea-sipping and scenery appreciation—arguably the most ideal spot for quiet contemplation in Lingering Garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_02.jpg', 1),
  ('suzhou_lingering_garden_sa_03', 'suzhou_lingering_garden', 'Hanbi Mountain House', '涵碧山房', 'Hanbi Mountain House is the principal hall in Lingering Garden''s central scenic area, facing north with three bays wide. It fronts a rippling pond and backs onto artificial hills and floral plantings—one of the garden''s premier vantage points. "Hanbi" derives from the Song dynasty poet Zhu Xi''s line "One water just embraces emerald," meaning water''s radiance contains verdant hues—an imagery of pristine expansiveness. The hall is bright and open, with scenic views both north and south: southward toward hills and ancient trees, northward over a pool mirroring the sky. The name encapsulates the idea that "both mountain and water are embraced within this house." This structure embodies the Suzhou garden design philosophy where hall and landscape are mutually constitutive—one sits indoors while scenery unfolds beyond the windows, interior and exterior seamlessly interwoven.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_03.jpg', 2),
  ('suzhou_lingering_garden_sa_04', 'suzhou_lingering_garden', 'Osmanthus Fragrance Pavilion', '闻木犀香轩', 'Osmanthus Fragrance Pavilion is located in the western scenic area of Lingering Garden, a pavilion-style structure expressly designed for appreciating the scent of osmanthus. "Muxi" is the classical term for osmanthus; the pavilion name plainly declares its design intent—enriching the garden''s sensory dimensions through olfactory experience. When golden osmanthus blooms in autumn, the pavilion is suffused with intoxicating fragrance; visitors inevitably pause to breathe deeply, marveling at the garden maker''s ingenuity in incorporating scent as scenery. Osmanthus trees are planted all around, complemented by rockery paths, forming a unique aesthetic space in Lingering Garden where olfaction takes precedence—breaking the convention of purely visual garden appreciation, and standing as a classic paradigm of "recognizing scenery through fragrance" in Chinese garden design.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_04.jpg', 3),
  ('suzhou_lingering_garden_sa_05', 'suzhou_lingering_garden', 'Winding Stream Tower', '曲溪楼', 'Winding Stream Tower stands in the eastern section of Lingering Garden, a two-story tower-style structure built beside the water. The name draws from the winding course of the garden''s waterway—"Winding Stream" is both descriptive and poetic: the actual winding stream and the metaphorical winding paths of life. The upper floor features open windows and a long railing; ascending for a distant view, the entire eastern water scene unfolds—winding bridges, corridor reflections, ripple layers upon layers. The lower floor has a waterside corridor for close viewing of stream stones and swimming fish. Winding Stream Tower offers the dual experience of "ascending for distant vistas" and "sitting by water to hear ripples," making it one of the most observationally versatile towers in Lingering Garden, and exemplifying the Suzhou garden design ingenuity of "scenery both above and below."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_05.jpg', 4),
  ('suzhou_lingering_garden_sa_06', 'suzhou_lingering_garden', 'Five Peaks Fairy Hall', '五峰仙馆', 'Five Peaks Fairy Hall is the core building of Lingering Garden''s eastern scenic area and the largest hall in the entire garden, spanning five bays with imposing grandeur. In the courtyard before the hall stand five Taihu stone peaks of varying heights and distinct postures, simulating the imagery of the five divine mountains where immortals dwell—hence the name. The hall''s structural materials are meticulously chosen: nanmu wood frames the beams and columns, with refined carvings that are exquisite yet not excessive, and elegant, dignified furnishings—reflecting the Jiangnan literati aesthetic of "grand yet not extravagant, refined yet not vulgar." This hall served as the garden owner''s principal venue for receiving distinguished guests and hosting elegant gatherings, with spacious yet well-layered interiors, standing as a paradigm of hall design in Suzhou gardens.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_06.jpg', 5),
  ('suzhou_lingering_garden_sa_07', 'suzhou_lingering_garden', 'Hall of Elderly Sages in Woodland Springs', '林泉耆硕之馆', 'Hall of Elderly Sages in Woodland Springs is located in the eastern part of Lingering Garden, adjacent to Five Peaks Fairy Hall, and is a distinctive double-facing hall. "Woodland Springs" refers to the reclusive environment of mountains, forests, and spring waters; "Elderly Sages" denotes venerable persons of high virtue and senior age. The hall name expresses the garden owner''s reverence and aspiration for reclusive scholars of distinction. Its architectural form is remarkable: one side faces the courtyard rockery, the other faces the pool and corridor pavilions—north and south scenes are strikingly different while the building remains seamlessly unified, representing the ultimate expression of "one hall, two views" in Suzhou garden design. Inscribed plaques and couplets inside are all by renowned calligraphers, with a strong literary atmosphere—arguably the building that best embodies the literati spirit at the core of Lingering Garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_07.jpg', 6),
  ('suzhou_lingering_garden_sa_08', 'suzhou_lingering_garden', 'Cloud-Capped Peak', '冠云峰', 'Cloud-Capped Peak is Lingering Garden''s most celebrated landmark and its crown jewel. Standing approximately 6.5 meters tall and weighing about 5 tons, it is the supreme specimen among Taihu stones, achieving the ultimate expression of the four aesthetic criteria: "slender, perforated, translucent, and wrinkled." The peak''s posture is majestic, its summit soaring like a crown piercing the clouds—hence the name. Legend holds it as a remnant of the Song dynasty''s "Flower and Stone Network" tribute collection; having endured a millennium of wind and rain, it remains standing here—the tallest independent Taihu stone peak surviving in Jiangnan gardens. Surrounded by pools, pavilions, and corridors, the stone''s silhouette reflects in the water, generating an interplay of reality and illusion that enhances its ethereal elegance. Stone appreciation is the essence of Chinese literati garden culture, and Cloud-Capped Peak stands as the pinnacle of this tradition.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_08.jpg', 7),
  ('suzhou_lingering_garden_sa_09', 'suzhou_lingering_garden', 'Cloud-Capped Tower', '冠云楼', 'Cloud-Capped Tower stands in the eastern part of Lingering Garden, built right beside Cloud-Capped Peak, a three-story tower-style structure. It shares the peak''s name because ascending the tower affords a complete panoramic view of Cloud-Capped Peak. The tower and peak form a classic "tower-peak opposing view"—looking down from the tower, the peak''s majestic upright posture is fully revealed; gazing up from the peak, the tower''s sweeping eaves and corner brackets are entirely displayed. The two resonate in height and complement each other in solidity and void, arguably the most brilliant pairing of architecture and stone peak in Suzhou gardens. Cloud-Capped Tower also houses important inscribed stone tablets and artifacts of Lingering Garden. Windows on the upper floors allow distant views beyond the garden across the Gusu cityscape—it is the scenic high point in Lingering Garden combining both close and distant observation functions.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lingering_garden_sa_09.jpg', 8),
  ('suzhou_ou_garden_sa_01', 'suzhou_ou_garden', 'Entrance Hall', '门厅', 'The Entrance Hall is the gateway space of Couple''s Garden Retreat—the garden''s first outward-facing aspect. Despite its renown as a Suzhou classic garden, its facade is understated, presented in the style of an ordinary residence, aligning with the Suzhou garden cultural tradition of "great reclusion within the city." The Entrance Hall is simple and unadorned—white walls, black tiles, no decorative carvings—aptly conveying the garden owner''s philosophy of retreating to pastoral life without seeking fame. Only after stepping through the Entrance Hall and past the screen door does the scenic beauty of mountains and water gradually reveal itself. This spatial sequence of "from simplicity to refinement" is a classic embodiment of Suzhou garden design''s "concealed scenery" technique at the entry point.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_01.jpg', 0),
  ('suzhou_ou_garden_sa_02', 'suzhou_ou_garden', 'Sedan Chair Hall', '轿厅', 'The Sedan Chair Hall sits between the Entrance Hall and the Main Hall, an indispensable transitional architectural space in traditional Suzhou residence-gardens. In former times, when the owner or guests arrived by sedan chair, the conveyance was parked here—hence the name. This hall is both a functional parking and waiting area and a transitional node in spatial rhythm—from the modest Entrance Hall through the Sedan Chair Hall into the Main Hall, building proportions gradually increase and decorations become more refined, forming a spatial progression of "from exterior to interior, from simplicity to splendor." The Sedan Chair Hall is proportionately sized—neither overshadowing nor appearing shabby—perfectly bridging the understated Entrance Hall and the dignified Main Hall, serving as the pivotal connecting link in Suzhou garden architectural sequences.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_02.jpg', 1),
  ('suzhou_ou_garden_sa_03', 'suzhou_ou_garden', 'Main Hall (Shequ Hall)', '大厅（涉趣堂）', 'The Main Hall, also named Shequ Hall, is the core building of Couple''s Garden Retreat''s residential area, spanning three bays with grand proportions—the principal venue for formal ceremonies and guest reception. "Shequ" derives from Tao Yuanming''s phrase "delving into delights as one goes," meaning following one''s interests and pleasures in exploration and experience—this is precisely the core philosophy of Couple''s Garden Retreat''s entire design: seeking not grand spectacle but rather abundant delight. The interior furnishings are dignified and elegant, with nanmu furniture complemented by paintings and calligraphy by renowned artists; the hall plaque "Shequ Hall" was inscribed by a prominent figure of the era. Courtyards exist both before and behind the hall—the front courtyard is open and square, the rear courtyard secluded and winding—within one hall, two entirely distinct spatial experiences are obtained, reflecting the Suzhou garden layout wisdom of "hall at center, divergent paths on either side."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_03.jpg', 2),
  ('suzhou_ou_garden_sa_04', 'suzhou_ou_garden', 'Upper Hall (Residence Tower)', '楼厅（寝居楼）', 'The Upper Hall, also called Residence Tower, lies at the rear of Couple''s Garden Retreat''s residential area—a two-story tower-style structure. The lower floor serves as daily living space with a reception room and study; the upper floor is the private sleeping quarters of the garden owner and family. The building''s scale is slightly smaller than the Main Hall, with warmer, more refined decorations, reflecting the transition from public ceremonial space to private living space. Rear windows overlook the garden''s rockery and lotus pool; front windows enjoy courtyard flowers and trees—it is a typical node where residence and garden intermingle. Occupants can experience garden beauty from within the tower without deliberately stepping out. This lifestyle of "living is touring, touring is living" embodies the essence of Suzhou''s integrated residence-garden culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_04.jpg', 3),
  ('suzhou_ou_garden_sa_05', 'suzhou_ou_garden', 'Study (Hanrui Study)', '书房（含蕊书斋）', 'Hanrui Study is the garden owner''s dedicated space for quiet study and contemplation in Couple''s Garden Retreat, situated at the junction between the residential area and the garden area—a small study with a serene environment and elegant furnishings. "Hanrui" means containing flower buds—potential within, yet unreleased—metaphorically referring to the literati practice of nurturing talent and awaiting the right moment, highly congruent with Couple''s Garden Retreat''s overall "reserved and understated" temperament. The study faces the garden side; beyond the windows, rockery and green bamboo are visible. Inside, the book collection is plentiful and writing materials are complete, creating an immersive ideal environment for reading and meditation. This was the daily space where garden owners Shen Bingcheng and his wife composed poetry, painted, sipped tea, and discussed scholarship—also one of the spiritual symbols of Couple''s Garden Retreat as a "couple''s shared reclusion" garden. In the study, the two shared the joy of reading in harmonious companionship.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_05.jpg', 4),
  ('suzhou_ou_garden_sa_06', 'suzhou_ou_garden', 'Entertainment Hall (Tinglu Hall)', '戏厅（听橹厅）', 'Tinglu Hall is a building space in Couple''s Garden Retreat rich in both everyday vitality and poetic imagination. "Tinglu" (listening to oars) derives from the garden''s unique geographical setting—the east side borders Suzhou''s ancient inner-city canal; sitting in the hall, one can hear the sound of boat sculls paddling through the water, hence the name. This hall served as the venue for the garden owner and his wife to enjoy music and performances, host banquets, and entertain guests—thus also called the Entertainment Hall. The interior is spacious enough for small performances and elegant gatherings. On the canal side, open windows bring the waterway''s sonic landscape indoors, forming a unique "sound scenery entering the room" experience. Suzhou is a water city; oar sounds are its urban auditory signature. Tinglu Hall employs hearing as a landscape design medium, integrating the city''s external living rhythm into the garden''s interior tranquility—a rare example of "constructing scenery through sound" in Suzhou gardens.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_06.jpg', 5),
  ('suzhou_ou_garden_sa_07', 'suzhou_ou_garden', 'Lotus Pond', '荷花池', 'The Lotus Pond is the core water feature space in Couple''s Garden Retreat''s garden area, and the visual and ecological center of the entire garden. The name is straightforward yet poetic—"ou" means lotus root; Couple''s Garden Retreat''s name itself is closely connected to the lotus, and the Lotus Pond is the living scenic source of this naming. Lotuses are planted throughout the pond; in summer, lotus leaves stretch to the horizon, red blossoms reflect the sun, and pure fragrance drifts far—harmonizing with the garden''s name. The pond''s banks wind with deliberate irregularity; corridors, bridges, and pavilions line the water, the surface reflecting rockery, pavilions, skylight, and cloud shadows—real and virtual interwoven like a painting. In Chinese culture, the lotus symbolizes purity and integrity. Couple''s Garden Retreat''s lotus theme is both a scenic choice and a spiritual commitment—the garden owners Shen Bingcheng and his wife used the lotus as a moral metaphor, embedding their aspirations for reclusive integrity among mountains, waters, flowers, and trees.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_07.jpg', 6),
  ('suzhou_ou_garden_sa_08', 'suzhou_ou_garden', 'Rockery', '假山', 'The Rockery is the three-dimensional landscape centerpiece of the garden area, located east of the Lotus Pond, constructed from Taihu stones. The mountain body rises and falls in staggered layers, with winding, deep paths forming a three-dimensional landscape scroll that is both explorable and visually appreciable. Though artificially constructed, the rockery pursues the natural ideal of "crafted by humans yet appearing as if created by nature"—stone peaks are rugged and graceful, caves are deep and intriguing, stone paths wind like real mountain stream courses. An observation platform atop the rockery offers panoramic views of the Lotus Pond and garden pavilions, with distant views of Suzhou''s cityscape beyond the walls. Stone caves and chambers beneath provide cool respite in summer—an ideal spot for escaping heat while enjoying scenery. Though not as grandly scaled as Lion Grove Garden''s rockery, Couple''s Garden Retreat''s rockery excels in refinement and subtlety, forming a classic "mountains encircling, waters surrounding" layout with the adjacent pond and pavilions.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_08.jpg', 7),
  ('suzhou_ou_garden_sa_09', 'suzhou_ou_garden', 'Hexagonal Pavilion (Ouxiang Pavilion)', '六角亭（藕香亭）', 'Ouxiang Pavilion is a hexagonal waterside pavilion in Couple''s Garden Retreat''s garden area, situated north of the Lotus Pond and facing the rockery across the water. The name "Ouxiang" (lotus root fragrance) directly highlights its defining feature—when lotus flowers bloom in summer, breezes carry their fragrance into the pavilion; sitting within to admire lotuses and inhale their scent constitutes the garden''s most poetically sensory experience. The hexagonal pavilion''s form is light and elegant, with open views on all six sides—every direction offers scenic entry: southward across the Lotus Pond, eastward to the majestic rockery, westward along winding corridors, northward toward the ancient city wall. Stone table and benches provide resting and tea-sipping spots—an ideal place for visitors to pause and immerse in garden scenery. Ouxiang Pavilion resonates most directly with the garden''s name—"ou" and "he" (lotus) share the same origin, "xiang" (fragrance) is the lotus''s essence—the pavilion name annotates the garden name, making it the garden''s signature thematic work.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_09.jpg', 8),
  ('suzhou_ou_garden_sa_10', 'suzhou_ou_garden', 'Winding Corridor', '回廊', 'The Winding Corridor is an essential architectural element threading together all scenic points in Couple''s Garden Retreat''s garden area, winding along the Lotus Pond''s edge, organically linking pavilions, terraces, towers, and halls with rockery and water into a complete observation sequence. The corridor is proportionately wide, with water on one side and walls or plantings on the other, forming a dual-view layout of "water on one side, wall on the other" or "scenes on both sides"—every step brings a different visual experience, representing the best practice of Suzhou garden''s "shifting views with each step" principle. The corridor roof follows Suzhou''s traditional corridor-pavilion construction: simple beams and columns, lightly sweeping eave corners. Every few steps, a pierced window opens—each uniquely shaped: round, square, plum blossom, or fan—through which different angles of pond and rockery scenes appear, making the corridor itself a flowing visual artwork. The corridor is not merely a traffic route but a carefully choreographed "visual narrative thread," guiding visitors to experience each garden scene in a designed rhythm.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_ou_garden_sa_10.jpg', 9),
  ('suzhou_pingjiang_road_sa_01', 'suzhou_pingjiang_road', 'Xiangmen Entrance', '相门入口', 'Xiangmen, also known as Jiangmen (Craftsman''s Gate), is one of the eight ancient gates of Suzhou, named after the legend that King Helu of Wu ordered swordsmiths to work here. The restored city wall now stands majestically at the southern end of Pingjiang Road, serving as the primary gateway for visitors entering this thousand-year-old historic block. The surrounding city wall heritage park is shaded by lush greenery, and climbing the wall offers panoramic views of the ancient city''s canal-and-alley landscape. It serves both as the starting point of a Pingjiang Road stroll and as a significant landmark for appreciating Suzhou''s city layout and gate culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_01.jpg', 0),
  ('suzhou_pingjiang_road_sa_02', 'suzhou_pingjiang_road', 'Yuan Bridge', '苑桥', 'Yuan Bridge spans the Pingjiang River as a classic stone arch bridge embodying the Jiangnan water-town aesthetic. Its name derives from the royal or private gardens that once graced its vicinity; though those gardens have faded into history, the bridge''s elegant form still evokes the prosperity of bygone eras. Standing on the bridge, one gazes east at whitewashed residences lining the canal and west at the winding flagstone path, where reflections and dwellings create a charming interplay. Yuan Bridge is not only a key node in Pingjiang Road''s dual water-and-land layout but also an ideal spot for photographers and visitors to capture the iconic imagery of "small bridge, flowing water, and humble home."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_02.jpg', 1),
  ('suzhou_pingjiang_road_sa_03', 'suzhou_pingjiang_road', 'Sipo Bridge', '思婆桥', 'Sipo Bridge is among the oldest bridges on Pingjiang Road. Legend attributes its name—"Sipo" meaning "remembering the granny"—to a kind old woman who offered tea and alms here; another theory links it to "Shipo" (female shaman or nun). Regardless of origin, this single-arch stone bridge has endured centuries of weather, its flagstones polished to a warm sheen by countless footsteps, its low rail blending seamlessly with the modest riverside dwellings. In morning mist or evening lamplight, Sipo Bridge paints a faint ink-wash canal scene, serving as one of the finest windows into Suzhou''s neighborhood philosophy that "bridges are life itself."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_03.jpg', 2),
  ('suzhou_pingjiang_road_sa_04', 'suzhou_pingjiang_road', 'Dingxiang Lane (Lilac Lane)', '丁香巷', 'Dingxiang Lane is a narrow, deeply secluded branch lane east of Pingjiang Road, named after the lilac trees that once filled it. In late spring and early summer, purple petals drift onto flagstones, perfuming the alley with a subtle fragrance. It also houses the former residence of the modern scholar Gu Jiegang, intertwining academic heritage with floral poetry. Old doorways stand half-open, cats dart past, and drying clothes coexist with carved lintels in a vivid neighborhood tableau. With its quietude and scent, Dingxiang Lane becomes the most moving literary corner beyond the bustling main street, drawing writers and wanderers who linger here in search of inspiration.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_04.jpg', 3),
  ('suzhou_pingjiang_road_sa_05', 'suzhou_pingjiang_road', 'Zhongzhangjia Lane (Suzhou Pingtan Museum)', '中张家巷（评弹博物馆）', 'Zhongzhangjia Lane is intimately tied to Pingtan culture. The Suzhou Pingtan Museum housed here is China''s only museum dedicated to Suzhou Pingtan (storytelling and musical performance). Its collections include extensive historical documents, manuscripts, records, and stage props tracing Pingtan''s evolution from the Qing dynasty to today. The highlight is the regular live performances: visitors can sit in a traditional storytelling house, sip Biluochun tea, and hear authentic Pingtan openings, experiencing the rhythmic cadence of Wu dialect singing and the delicate accompaniment of stringed instruments. This is an essential hall for understanding Suzhou''s "sound culture" and Pingjiang Road''s most vibrant site of living heritage.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_05.jpg', 4),
  ('suzhou_pingjiang_road_sa_06', 'suzhou_pingjiang_road', 'Niujia Lane (Suzhou Zhuangyuan Museum)', '钮家巷（状元博物馆）', 'The Suzhou Zhuangyuan Museum on Niujia Lane is set within Fengchi Garden, the former residence of Qing dynasty Zhuangyuan Pan Shi''en. Suzhou has produced over fifty Zhuangyuan since the Song dynasty—more than any other city in China—earning the title "Home of Zhuangyuan." Using Pan Shi''en''s life as an entry point, the museum displays exam papers, honor plaques, robes, and daily artifacts, comprehensively illustrating the journey from arduous study to imperial triumph and the profound influence of Zhuangyuan families on Suzhou''s educational traditions. The residence itself is an elegant Suzhou mansion with spacious halls and graceful landscaping, allowing visitors to appreciate the layout aesthetics of Jiangnan scholar-official dwellings alongside the exhibits. It is a cultural hall where scholarly spirit and architectural beauty merge seamlessly.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_06.jpg', 5),
  ('suzhou_pingjiang_road_sa_07', 'suzhou_pingjiang_road', 'Daru Lane (Great Scholar Lane)', '大儒巷', 'Daru Lane takes its name from the renowned Ming dynasty scholar Wang Ren—"Daru" (Great Scholar) itself distills Suzhou''s reverence for learning. Several Ming and Qing residences and scholar sites still survive here, their blue-brick gateways and lattice windows hinting at a bygone literary aura. Meanwhile, Daru Lane is also one of Pingjiang Road''s most concentrated artisan branches, dotted with Su embroidery studios, nut-carving workshops, and woodwork shops, where literati ethos and craftsman spirit run parallel. The lane''s intimate scale and sparse foot traffic invite unhurried exploration, allowing visitors to read between doorways and window frames the symbiotic humanistic ecology of Suzhou''s "letters and crafts."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_07.jpg', 6),
  ('suzhou_pingjiang_road_sa_08', 'suzhou_pingjiang_road', 'Xuanqiao Lane (Hong Jun''s Former Residence & Boat House)', '悬桥巷（洪钧故居、船屋）', 'Xuanqiao Lane, named after a suspension bridge that once stood at its entrance, is Pingjiang Road''s most legendary branch. No. 27 is the former residence of late-Qing Zhuangyuan Hong Jun, who served as envoy to several European nations and later lived here with the famous courtesan Sa Jinhua—a story still avidly recounted. The residence''s most distinctive feature is a "boat house"—an entire building constructed in the shape of a boat, with two cabins and orderly hull-style lattice windows, resembling a dry-docked vessel in the lane, standing as Suzhou''s most creative singular example of residential architecture. The lane itself is deep and tranquil, old eaves intertwining with creeping vines; a stroll here feels like walking into a fold of late-Qing turbulence compressed by time.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_08.jpg', 7),
  ('suzhou_pingjiang_road_sa_09', 'suzhou_pingjiang_road', 'Qingshi Bridge (Bluestone Bridge)', '青石桥', 'Qingshi Bridge, named for its bluestone construction, is one of Pingjiang River''s most understated yet evocative ancient bridges. The bridge vicinity is Pingjiang Road''s most lived-in stretch, where several canal-side teahouses extend wooden awnings with tables half-reaching over the water. As patrons sip tea and chat, awning boats glide slowly beneath the bridge, composing a living water-town tableau. Qingshi Bridge is also among the most enchanting night scenes on Pingjiang Road: after dark, lantern reflections float on the canal, teahouse warm light mirrors on the water, and the ancient bridge silhouette flickers between brightness and shadow. We recommend lingering at least half an hour—sit in a bridge-side teahouse and, over a cup of Suzhou Biluochun tea, truly read Pingjiang Road''s philosophy that "slowness is beauty."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_09.jpg', 8),
  ('suzhou_pingjiang_road_sa_10', 'suzhou_pingjiang_road', 'Quanjin Guild Hall - Suzhou Chinese Opera Museum', '全晋会馆 - 苏州戏曲博物馆', 'Quanjin Guild Hall is Pingjiang Road''s most architecturally stunning landmark. Built with funds raised by Shanxi merchants doing business in Suzhou during the Qianlong era, it served for fellow-provincial gatherings and business deliberations. The hall''s most striking feature is its theater building: above the stage, a caisson ceiling composed of hundreds of carved wooden components stacked into an inverted dome, painted red and gold, stands as one of the finest surviving ancient theater caissons in the Jiangnan region. Today the guild hall has been transformed into the Suzhou Chinese Opera Museum, displaying artifacts and visual materials of Kunqu, Peking Opera, Su Opera, and other genres, with regular Kunqu performances. This building is both a historical imprint of Shanxi merchants in Suzhou and a three-dimensional textbook of Chinese traditional opera art.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_pingjiang_road_sa_10.jpg', 9),
  ('suzhou_lion_grove_garden_sa_01', 'suzhou_lion_grove_garden', 'Yanyu Hall (Hall of Swallow''s Honor)', '燕誉堂', 'Yanyu Hall is Lion Grove Garden''s main hall and the first building visitors encounter. "Yanyu" derives from the Shijing (Book of Odes): "The gentleman has wine, and the guests feast joyfully"—where "Yan" means banquet and "Yu" means delight. The hall''s interior is elegantly appointed, with screen paintings depicting Lion Grove panoramas and poetic inscriptions by masters past. Through the windows, the garden''s lake-stone labyrinth already looms tantalizingly. Yanyu Hall establishes the garden''s tone of festive exploration, signaling that Lion Grove is not merely for contemplation but for a sensory adventure brimming with playfulness.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_01.jpg', 0),
  ('suzhou_lion_grove_garden_sa_02', 'suzhou_lion_grove_garden', 'Xiaofang Hall (Small Square Hall)', '小方厅', 'Xiaofang Hall sits directly north of Yanyu Hall—a small yet meticulously designed square hall. The name "Xiaofang" refers both to its regular square plan and to the garden philosophy of "seeing the cosmos within a square inch." Its most ingenious feature is the window design: east and west ornamental windows act as picture frames, precisely cropping different fragments of the rockery group, so that standing inside, visitors preview sections of the stone labyrinth they will soon enter. This framing technique turns the diminutive hall into a visual prelude for the entire rockery. The interior is restrained—simple furnishings and blank walls creating an austere elegance that contrasts brilliantly with the rugged lake stones beyond the windows, a dialogue of softness and strength.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_02.jpg', 1),
  ('suzhou_lion_grove_garden_sa_03', 'suzhou_lion_grove_garden', 'Nine Lion Peak', '九狮峰', 'Nine Lion Peak is the rockery group''s most arresting element and the most direct visual proof of the garden''s naming origin. Composed of multiple Taihu (lake) stones assembled in their natural forms, its overall silhouette and surface undulations reveal lion shapes—some head-raised, some crouching, some playing, some guarding. Careful observation identifies nine lions in distinct, vivid poses. Lion Grove Garden was built by Yuan dynasty monk Tianru to honor his master Zhongfeng; "lion" refers both to the rockery''s lion-like forms and to the Buddhist metaphor of the "lion''s roar" symbolizing the power of enlightenment preaching. Nine Lion Peak stands at the rockery entrance between Xiaofang Hall and Zhibai Pavilion, serving as both the labyrinth''s landmark and a extraordinary work where Buddhist Chan philosophy and secular stone-appreciation aesthetics intersect.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_03.jpg', 2),
  ('suzhou_lion_grove_garden_sa_04', 'suzhou_lion_grove_garden', 'Zhibai Pavilion (Point-to-Cypress Pavilion)', '指柏轩', 'Zhibai Pavilion is the main viewing hall on the south side of the rockery group. Its name originates from a Chan (Zen) koan: when a monk asked Zhaozhou Congshen, "What is the meaning of the Patriarch''s coming from the West?" Zhaozhou replied, "The cypress tree in the courtyard"—pointing to an ordinary object to expound the dharma''s essence, transcending textual convention. Zhibai Pavilion embodies this Chan spirit in garden architecture: an ancient cypress stands verdant and upright before the hall, rugged lion-shaped rocks behind it; from within, one can survey the entire stone labyrinth while contemplating the Chan insight that "the path is right before your eyes." The pavilion once served as a monk''s meditation space, later transforming into a literati gathering place, with poetic inscriptions on screen panels. It is Lion Grove''s building where Buddhist Chan thought and Jiangnan garden viewing are most tightly interwoven.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_04.jpg', 3),
  ('suzhou_lion_grove_garden_sa_05', 'suzhou_lion_grove_garden', 'Hualan Hall (Flower Basket Hall)', '花篮厅', 'Hualan Hall is an exquisite hall on the south side of Lion Grove''s pool, named after the flower-basket motifs carved on its dangling-lotus columns (short eaves columns). These carved flower baskets demonstrate superb craftsmanship—each basket holds different blooms: peony, lotus, plum, or orchid, with flowing lines and layered depth, representing the finest of Suzhou garden wood-carved ornamentation. The hall is partially built over the water, its base partly submerged in the pool. Sitting inside, one views the pool reflections and the full rockery panorama opposite, where rippling light and rugged peaks converge, creating the uncanny visual experience of "the hall in the water, the mountain in the mirror." Interior displays follow a floral theme, with seasonal vase flowers creating an engaging contrast between "carved flowers" and "real flowers."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_05.jpg', 4),
  ('suzhou_lion_grove_garden_sa_06', 'suzhou_lion_grove_garden', 'Zhenqu Pavilion (True Delight Pavilion)', '真趣亭', 'Zhenqu Pavilion sits beside the pool on the east side of the rockery group, the garden''s building most deeply connected to Emperor Qianlong. During his six southern tours, Qianlong visited Lion Grove each time; on one occasion, lost in delight within the rockery maze, he brush-wrote "Zhen You Qu" (truly interesting). A accompanying minister deemed "You Qu" too colloquial and tactfully suggested keeping "Zhen" and changing to "Qu" (delight), preserving imperial joy while elevating literary refinement—Qianlong gladly agreed. "Zhen Qu" (True Delight) carries both the documentary sense of the emperor''s garden pleasure and the Chan philosophical dimension of "true suchness"—only by playful wandering in the labyrinthine rockery does one attain life''s "true delight." The plaque remains preserved inside the pavilion, one of Lion Grove''s most precious historical artifacts.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_06.jpg', 5),
  ('suzhou_lion_grove_garden_sa_07', 'suzhou_lion_grove_garden', 'Stone Boat', '石舫', 'The Stone Boat is a boat-shaped water structure in Lion Grove''s pool, entirely constructed of stone with realistic bow, cabin, and stern forms, stone railings along the sides, and stone tables and benches inside for resting. Fixed in place, it is called an "untethered boat"—an image derived from Zhuangzi''s philosophical parable of drifting "like an untethered boat," symbolizing spiritual freedom and non-attachment. The stone boat is a highly representative Jiangnan garden building type: it fulfills the desire to linger on water while creating unique aesthetic tension through the static paradox of "a boat that stays, water that moves." Sitting inside the cabin, surrounded by water on all sides, pool reflections and distant rockery compose a framed view—as if truly boating on a lake yet without risk of wind or waves, achieving playful delight between reality and illusion.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_07.jpg', 6),
  ('suzhou_lion_grove_garden_sa_08', 'suzhou_lion_grove_garden', 'Anxiang Shuying Building (Faint Scent & Sparse Shadows Building)', '暗香疏影楼', 'Anxiang Shuying Building sits at the northwest corner of Lion Grove, a two-story pavilion themed around plum appreciation. Its name draws from the Northern Song recluse Lin Bu''s immortal plum verses: "Sparse shadows slant across clear shallow water; faint scent drifts at moonlit dusk"—two lines that virtually defined the plum blossom aesthetic standard in Chinese culture: sparse branches, subtle fragrance. Several ancient plum trees grow before the building; in winter bloom, ascending the upper floor reveals branch shadows reflected in the pool and delicate fragrance drifting through windows, making the poem''s imagery tangibly realized through direct sensory experience. Interior displays include related poetic calligraphy and paintings; window lattice designs deliberately lower the sightline to match plum-viewing angles. From naming to spatial design, the building is tightly bound to the plum theme—an outstanding example of translating poetic imagery into architectural experience at Lion Grove.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_08.jpg', 7),
  ('suzhou_lion_grove_garden_sa_09', 'suzhou_lion_grove_garden', 'Huxin Pavilion (Lake-Center Pavilion)', '湖心亭', 'Huxin Pavilion occupies the exact center of Lion Grove''s main pool—a single-story hexagonal pavilion connected to both banks by stone curved bridges. Though small, it holds the absolute core of the garden''s spatial composition: standing inside with a 360-degree panorama, the rockery group, Zhibai Pavilion, Hualan Hall, Stone Boat, and other major scenes encircle the view like a painting; the pavilion itself becomes a borrowed-view object for other buildings, creating a mutual viewing relationship of "the pavilion as center, every scene seeing every scene." Huxin Pavilion''s design embodies Suzhou garden''s essence of "seeing the vast through the small": the smallest-volume building placed at the center of the largest-scale water surface, the pavilion''s transparency in exchange for the pool''s sense of expansiveness—inside, one does not feel the pavilion small but the pool vast. Under morning light or evening shadow, the pavilion floats on the water as one of Lion Grove''s most photogenic spots.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_09.jpg', 8),
  ('suzhou_lion_grove_garden_sa_10', 'suzhou_lion_grove_garden', 'Woyun Chamber (Cloud-Reclining Chamber)', '卧云室', 'Woyun Chamber occupies the highest point of Lion Grove''s rockery—the garden''s highest-altitude building and the only Chan meditation space embedded within a stone peak. "Woyun" (Cloud-Reclining) is richly poetic and Chan-inflected: clouds above, the chamber amid the rocks, the person inside seemingly resting on clouds looking down at the mortal world; it also echoes monk Tianru''s "cloud-and-water Chan mind" practice philosophy. The chamber is extremely small, accommodating only a few seated people, austere inside—just meditation cushions and a simple table contrasting with the rough stone walls outside. Gazing outward, rock tunnels, pool ripples, and distant garden walls compose a framed view; the spatial elevation confers a genuine sense of psychological detachment—looking down from the "clouds" upon the "red dust." This is Lion Grove''s most exquisite work of embedding architecture within rockery, and the supreme expression of Chan philosophy merged with garden art.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_lion_grove_garden_sa_10.jpg', 9),
  ('suzhou_museum_sa_01', 'suzhou_museum', 'Entrance Hall', '入口大厅', 'The Entrance Hall serves as the welcoming space of Suzhou Museum''s new wing, masterfully designed by the world-renowned architect I.M. Pei. Clean geometric lines and expansive glass walls create a luminous, airy atmosphere, while natural light streaming through skylights casts shifting shadows across white walls and gray eaves. A guide desk and multimedia displays provide comprehensive visitor information. From the hall, glimpses of the rockery in the main courtyard already reveal a dialogue between ancient and modern aesthetics.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_01.jpg', 0),
  ('suzhou_museum_sa_02', 'suzhou_museum', 'Wu Region Heritage Gallery', '吴地遗珍展厅', 'The Wu Region Heritage Gallery brings together important archaeological finds from Suzhou, ranging from Shang-Zhou bronze wares to Spring-and-Autumn jade pieces, from Han dynasty pottery figurines to Six Dynasties celadon. Three thematic sections — "Origins of Wu," "Artifacts of Wu," and "Spirit of Wu" — weave a continuous narrative, allowing visitors to experience Suzhou''s deep cultural accumulation through individual objects. Bronze swords and primitive porcelain jars are especially prized, testifying to the extraordinary metallurgical and ceramic skills of Wu''s early inhabitants. This gallery is essential for understanding the roots of Jiangnan culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_02.jpg', 1),
  ('suzhou_museum_sa_03', 'suzhou_museum', 'Wu Pagoda National Treasures Gallery', '吴塔国宝展厅', 'The Wu Pagoda National Treasures Gallery is one of the museum''s most compelling spaces, concentrating national-treasure-grade artifacts discovered inside Huqiu Yunyan Temple Pagoda and Ruiguang Pagoda. The Yue kiln mise (secret-color) porcelain lotus bowl from Huqiu, its glaze as green as lake water, is widely acknowledged as the pinnacle of late Tang–Five Dynasties secret-color porcelain. The Pearl Relic Stupa from Ruiguang Pagoda, intricately carved from pearls, gems, and sandalwood, astonishes the world with its craftsmanship. These relics not only reveal the depth of Wu''s Buddhist culture but also represent the zenith of Suzhou craftsmanship before the Song dynasty — an unmissable highlight of any visit.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_03.jpg', 2),
  ('suzhou_museum_sa_04', 'suzhou_museum', 'Wu Elegance Gallery', '吴中风雅展厅', 'The Wu Elegance Gallery follows a timeline from the Song dynasty to the Ming-Qing era, using studio implements, tea ware, incense sets, and guqin to vividly recreate the "ya" (refined) lifestyle of Suzhou''s literati class. Sections such as "Study Treasures," "Tea and Zen," and "Qin, Qi, Shu, Hua" allow visitors to glimpse how ancient Suzhou scholars pursued spiritual transcendence and aesthetic perfection in daily life. Each exquisite inkstone, warm tea cup, and understated incense burner speaks to the Wu literati''s ideal of embodying philosophy through objects. The gallery displays not only the beauty of artifacts but also a Jiangnan philosophy of life spanning a millennium.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_04.jpg', 3),
  ('suzhou_museum_sa_05', 'suzhou_museum', 'Wu School Calligraphy & Painting Gallery', '吴门书画展厅', 'The Wu School Calligraphy & Painting Gallery is one of the museum''s most artistically significant spaces, systematically collecting and displaying core works of the Ming-dynasty Wu School. Shen Zhou''s robust and moist brushwork, Wen Zhengming''s refined precision, Tang Yin''s spirited fluidity, and Qiu Ying''s exquisite grace — the four Wu masters each achieved brilliance in their own style, collectively shaping the pinnacle of Ming literati painting. The gallery also features Wu School calligraphy, from Zhu Yunming''s wild cursive script to Wen Zhengming''s small regular script, revealing Wu literati''s talent and character in every stroke. Rotating thematic exhibitions ensure new discoveries on each visit — an essential destination for lovers of calligraphy and painting in Suzhou.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_05.jpg', 4),
  ('suzhou_museum_sa_06', 'suzhou_museum', 'Neolithic Jade Gallery', '新石器时代玉器展厅', 'The Neolithic Jade Gallery focuses on jade treasures from the Neolithic period in the Lake Tai region, especially the Liangzhu culture. Jade bi discs, cong tubes, axe heads, and huang pendants — these forms carried ancient reverence for heaven and earth and symbolized authority; their finely incised patterns and polished surfaces are awe-inspiring. The gallery restores the archaeological context of these jades, helping visitors understand that they were not mere ornaments but ritual implements for communicating with deities and marking social rank. The god-and-animal mask motif on Liangzhu cong is considered one of the earliest divine emblems of Chinese civilization, holding irreplaceable academic value for exploring East Asian civilizational origins.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_06.jpg', 5),
  ('suzhou_museum_sa_07', 'suzhou_museum', 'Main Courtyard (Slice Rockery)', '主庭院（片石假山）', 'The Main Courtyard is the most iconic space in Suzhou Museum''s new wing, conceived and designed by I.M. Pei himself. Using white walls as canvas and sliced rocks as brushstrokes, he transforms Mi Fu''s "Mi-style cloud mountains" from ink painting into a three-dimensional landscape. Gray rock slices, staggered and layered against white walls, appear like distant peaks emerging through mist, breaking from traditional rockery stacking to create an unprecedented "wall-as-canvas, stone-as-painting" modern garden aesthetic. The courtyard''s mirror-like water, sparse bamboo shadows, and views across the wall to the Humble Administrator''s Garden form a natural dialogue between old and new — I.M. Pei''s enduring gift to Suzhou.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_07.jpg', 6),
  ('suzhou_museum_sa_08', 'suzhou_museum', 'Wisteria Garden', '紫藤园', 'The Wisteria Garden occupies the transitional zone between the new wing and the Loyal King''s Mansion, the museum''s most poetic small garden space. The wisteria vines originate from centuries-old stock inside the Loyal King''s Mansion; I.M. Pei personally grafted them here, enabling this time-spanning life to continue blossoming in the new wing. Each April, wisteria cascades like a waterfall, purple petals swaying in the breeze against white walls and gray tiles in stunning color contrast. Stone paths wind beneath the canopy, light dappling through leaves — a moment''s pause here reveals Pei''s deeper design philosophy using plants as living links: new and old are not severed but share the same roots.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_08.jpg', 7),
  ('suzhou_museum_sa_09', 'suzhou_museum', 'Tea Room', '茶室', 'The Tea Room sits on the west side of the new wing, with expansive floor-to-ceiling glass directly facing the Main Courtyard''s slice-rock rockery and water feature — the museum''s most restorative retreat. Suzhou Biluochun is the signature brew, accompanied by local tea snacks, inviting visitors to slow their pace with a cup of clear tea after viewing exhibitions. The design extends Pei''s minimalist aesthetic: gray-white tones with wooden furniture, landscape paintings beyond the glass, tea mist within, merging into a distinctive Zen atmosphere. Whether for a leisurely afternoon sit or a brief inter-exhibition pause, the Tea Room transforms the museum visit into a sensory pleasure.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_09.jpg', 8),
  ('suzhou_museum_sa_10', 'suzhou_museum', 'Taiping Heavenly Kingdom Loyal King Mansion', '太平天国忠王府', 'The Loyal King''s Mansion is a core component of Suzhou Museum, originally the Suzhou residence of the Taiping Heavenly Kingdom''s Loyal King Li Xiucheng, built around 1860. It is one of the best-preserved Taiping historical buildings in China, where classical Suzhou palace layout coexists with distinctive Taiping decorative elements — dragon carvings, painted murals, and Taiping inscriptions forming unique layers of historical information. The indoor classical stage inside is a rare large-scale theater in Jiangnan, its caisson ceiling carved with breathtaking finesse. Connected to Pei''s new wing, stepping from the classical halls into the modern space crosses a century in a single stride, giving the tension between history and contemporary its most vivid expression.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_museum_sa_10.jpg', 9),
  ('suzhou_huanxiu_mountain_villa_sa_01', 'suzhou_huanxiu_mountain_villa', 'Yougu Hall (Hall of Abundant Grain)', '有穀堂', 'Yougu Hall sits at the front of the entrance axis of Huanxiu Mountain Villa, serving as the first hall visitors encounter, fulfilling both welcoming and ceremonial functions. The name "Yougu" derives from the Analerta, where "gu" carries the dual meaning of virtue and blessing, symbolizing abundance in goodness and fortune. The hall spans three bays with a flush gable roof, on all sides—facing the entrance courtyard to the south and the main pond to the north—serving as the transitional space connecting the front and rear garden areas. The timber frame is finely crafted, the furnishings simple, with a plaque suspended at the center. Though modest in scale, its clear axial relationship creates a dialogue with the main rockery; gazing north from within, Ge Yuliang''s masterpiece comes into full view, establishing the classic "hall facing mountain" layout that defines the garden''s spatial structure.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_01.jpg', 0),
  ('suzhou_huanxiu_mountain_villa_sa_02', 'suzhou_huanxiu_mountain_villa', 'Huanxiu Mountain Villa (Four-Side Hall)', '环秀山庄（四面厅）', 'The Four-Side Hall is situated north of the main pond and serves as the garden''s central viewing structure. Spanning five bays with corridors on all four sides and continuous windows on each elevation, it earns its name by offering views in every direction. Facing the pond with Ge Yuliang''s main rockery directly across the water, it is the premier spot for viewing the rockery in its entirety. Though the largest building in the garden, its well-proportioned dimensions maintain an intimate human scale without feeling oppressive. The hall originally bore the plaque "Huanxiu Mountain Villa," from which the garden takes its name. As the visual focal point and spatial hub, visitors can gaze north at the majestic main peak and deep caves, east at the side galleries, west at the towering Hanyun Pavilion, and south at the pond''s reflections, embodying the Suzhou principle of a hall as the eye of the garden with scenery on all sides.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_02.jpg', 1),
  ('suzhou_huanxiu_mountain_villa_sa_03', 'suzhou_huanxiu_mountain_villa', 'Ge Yuliang Rockery', '戈裕良假山', 'The Ge Yuliang Rockery is the soul of Huanxiu Mountain Villa, constructed by the Qing dynasty master Ge Yuliang during the Jiaqing reign. Covering less than half a mu with a main peak exceeding seven meters in height, it creates a majestic landscape of undulating ridges, deep caves, and intersecting ravines, hailed by garden scholar Chen Congzhou as "the crown of Chinese classical garden rockeries." Ge pioneered the "grand axe-cut texture" technique, stacking Lake Tai stones into precipitous cliffs, flying stone bridges, and hidden grottoes with running water beneath. The rockery is fully explorable: stone paths spiral to the summit for panoramic views, while tunnels offer an immersive journey through shifting spatial experiences. It represents the supreme realization of the classical ideal of a garden that is both "tourable and inhabitable," possessing unparalleled artistic and historical value.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_03.jpg', 2),
  ('suzhou_huanxiu_mountain_villa_sa_04', 'suzhou_huanxiu_mountain_villa', 'Hanyun Pavilion (Cloud-Encompassing Pavilion)', '涵云阁', 'Hanyun Pavilion stands on the western side of Huanxiu Mountain Villa, a two-story tower built flush against the garden wall. The name "Hanyun" means "encompassing clouds," alluding to its lofty presence. The structure is diminutive yet precisely proportioned, with a masonry ground floor and a timber upper story featuring latticed windows on all sides. As the highest point in the garden, the upper floor offers a bird''s-eye view of the Ge Yuliang Rockery, complementing the ground-level perspective from the Four-Side Hall. Though compact inside, the windows reveal the rockery appearing as a real mountain nearby, while the distant city skyline is borrowed as scenery beyond, showcasing the garden''s masterful manipulation of scale. The pavilion is also the optimal vantage for observing the rockery''s layered composition and stacking technique from the side.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_04.jpg', 3),
  ('suzhou_huanxiu_mountain_villa_sa_05', 'suzhou_huanxiu_mountain_villa', 'Side Building and Corridor', '边楼与边廊', 'The Side Building and Corridor run along the eastern wall of Huanxiu Mountain Villa, serving as the connective tissue linking the garden''s various zones. The Side Building is two stories—a corridor below and rooms above—joined with the corridor in a rhythmic high-low sequence. The corridor winds and turns, sometimes hugging the wall, sometimes opening to views, adjusting its path in response to terrain and landscape, embodying the Suzhou principle of "corridors guiding visitors, scenery shifting with every step." Lattice windows and moon gates along the corridor frame views of the rockery, pond, and plantings like a series of landscape paintings unrolled in sequence. The upper floor also provides an elevated vantage for observing the eastern face of the rockery, combining circulation and viewing functions.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_05.jpg', 4),
  ('suzhou_huanxiu_mountain_villa_sa_06', 'suzhou_huanxiu_mountain_villa', 'Wenquan Pavilion (Spring-Inquiring Pavilion)', '问泉亭', 'Wenquan Pavilion stands near the Feixue Spring ruins within Huanxiu Mountain Villa, a small square pavilion built specifically for viewing the spring and its surrounding rock-and-water composition. The name "Wenquan" (Inquiring After the Spring) carries refined literati sensibility, personifying the spring with a sense of seeking and inquiry, reflecting the garden owner''s cherishing of and intimacy with the natural water source. The pavilion features a four-sided pyramidal roof on four columns, light and open, blending seamlessly with the adjacent rockery and stone paths. From within, visitors can observe the spring''s outlet and the interplay of water and stone up close, listening to the murmuring flow and appreciating the poetic notion of inquiring how the spring stays so clear. Surrounded by Lake Tai stones and ancient trees, it is one of the most serene rest stops in the garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_06.jpg', 5),
  ('suzhou_huanxiu_mountain_villa_sa_07', 'suzhou_huanxiu_mountain_villa', 'Buqiu Studio (Autumn-Compensating Studio)', '补秋舫', 'Buqiu Studio is located east of the main rockery within Huanxiu Mountain Villa, a land-boat structure representing a common Suzhou garden archetype. The front mimics a prow, the rear corridor suggests a stern, and the central cabin features latticed windows on both sides, the whole resembling a painted pleasure boat moored among rocks. The name "Buqiu" (Compensating for Autumn) implies that this spot makes up for any insufficiency in autumn scenery, reflecting the owner''s fondness for autumn colors. The studio faces the eastern foot of the rockery, where autumn maples blaze against the yellow-stone rocks in a riot of color, fulfilling the "buqiu" aspiration. The land-boat form satisfies viewing needs while the nautical imagery evokes water and reverie, bringing the delight of boating to a waterless setting, exemplifying the Suzhou technique of substituting meaning for scenery and interweaving the real and the imagined.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_07.jpg', 6),
  ('suzhou_huanxiu_mountain_villa_sa_08', 'suzhou_huanxiu_mountain_villa', 'Bantan Qiushui Yifangshan Pavilion (Half-Pond Autumn Water and One-Room Mountain Pavilion)', '半潭秋水一房山亭', 'Bantan Qiushui Yifangshan Pavilion crowns the summit of the main rockery, the highest viewing point in Huanxiu Mountain Villa. The highly poetic name derives from Song dynasty verse: "half a pond of autumn water" refers to the pool seen below, and "one room of mountain" describes the rocks surrounding the pavilion, seamlessly fusing location and vista. The hexagonal pavilion is diminutive, accommodating only a few, perched on the main peak with eaves like wings ready to take flight. Reaching it requires spiraling up steep, narrow stone paths through deep grottoes, culminating in a sudden panoramic revelation. From within, the entire garden—pond, rockery, and architecture—unfolds below, with the half-pond at its foot and rocks filling the view, perfectly matching its name. It is the ultimate vantage for experiencing Ge Yuliang''s art of "vast mountains in a miniature space" and the most poetically evocative spot in the garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_08.jpg', 7),
  ('suzhou_huanxiu_mountain_villa_sa_09', 'suzhou_huanxiu_mountain_villa', 'Feixue Spring Ruins', '飞雪泉遗址', 'The Feixue Spring Ruins lie at the southwestern foot of the rockery in Huanxiu Mountain Villa, marking the site of the garden''s most important historical water source. Named for its spray resembling flying snow, the spring once yielded clear, cold water that fed the streams running through the rockery, contributing to the villa''s name. When Ge Yuliang constructed the rockery during the Qing dynasty, he channeled this spring to the summit, creating a cascade that tumbled through the rocks, animating the rockery with the dynamic interplay of mountain and water. Though the spring has since run dry, the surrounding rockwork, pool walls, and stone channels remain intact, allowing visitors to imagine the former spectacle of cascading water. The ruins, with their craggy Lake Tai stones, ancient vines, and mottled moss, exude a beauty of desolate antiquity—a place to contemplate the passage of time and the garden''s historical transformation.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_huanxiu_mountain_villa_sa_09.jpg', 8),
  ('suzhou_tongli_ancient_town_sa_01', 'suzhou_tongli_ancient_town', 'Tuisi Garden (Retreat & Reflection Garden)', '退思园', 'Built in the Guangxu era of the Qing dynasty, the garden was constructed by Ren Lansheng after his dismissal from office, named after the Zuo Zhuan phrase "Advance to serve with loyalty, retreat to reflect and mend faults." Though only 9.8 mu in area, its masterly layout creates infinite poetic resonance within limited space — pavilions, towers, pools, rockeries, flowers, trees, corridors, and bridges. All buildings are constructed flush against the water, forming a "water-hugging" architectural ensemble including Spring View Tower, Cool Arrowroot Rain Pavilion, and Osmanthus Hall. The mirror-like water reflects pavilions, merging reality and illusion. As a UNESCO World Heritage site and Tongli''s core attraction, its "seeing the vast in the small" design philosophy is hailed as the paradigm of Jiangnan gardens.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_01.jpg', 0),
  ('suzhou_tongli_ancient_town_sa_02', 'suzhou_tongli_ancient_town', 'Pearl Tower', '珍珠塔', 'The Pearl Tower is not a physical tower, but the combined name of a long-celebrated opera story in Tongli and the associated Chen family mansion. The tale tells of Fang Qing, a Tongli noble fallen into poverty, seeking help from his aunt Chen Cuie; the Chen family pretended to gift a pearl tower but actually hid silver within it to aid Fang Qing, eventually leading to a happy ending. This "Pearl Tower" legend has been adapted into Suzhou pingtan (storytelling) and opera, becoming Tongli''s most famous folk narrative. The restored Chen mansion is now open to visitors, with displays and scene reconstructions related to the story, allowing guests to relive this tale of Jiangnan loyalty and deep affection spanning centuries.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_02.jpg', 1),
  ('suzhou_tongli_ancient_town_sa_03', 'suzhou_tongli_ancient_town', 'Three Bridges', '三桥', 'The Three Bridges are Tongli''s most iconic landscape — three ancient stone bridges spanning the town''s central waterways: Taiping (Peace), Jili (Good Fortune), and Changqing (Lasting Celebration). Arranged in a "" (pin) pattern close together, they form the visual focal point of Tongli''s waterside space. In local tradition, newlyweds must walk the three bridges for blessings of peace, fortune, and lasting joy; residents also stroll the bridges during festivals to pray for good luck — a custom sustained for centuries. Below the bridges, emerald water flows gently; on both banks, white walls and black tiles; on the bridges, pedestrians stream; beneath them, boats pass — the most vivid frame of Tongli''s waterside life scroll, and photographers'' favorite angle.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_03.jpg', 2),
  ('suzhou_tongli_ancient_town_sa_04', 'suzhou_tongli_ancient_town', 'Chongben Hall', '崇本堂', 'Built in the Xuantong era of the Qing dynasty, Chongben Hall was the residence of wealthy Tongli merchant Qian Youqin, named for the principle of "honoring roots and reflecting on origins." Though modest in scale, it stands out among Tongli''s ancient architecture for its exceptionally refined brick-carved gate towers and wood-carved decorations. The gate tower''s brick carvings are richly layered, depicting theatrical tales and auspicious motifs with meticulous knife work; interior wood-carved doors and windows render scenes from The Romance of the Western Chamber and other operas with lifelike figures. Built along the river in three progressive courtyards — from entrance hall to main hall to inner quarters — it embodies the typical Jiangnan residential pattern of "front hall, rear dwelling," a precious case study of Tongli merchant-class life.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_04.jpg', 3),
  ('suzhou_tongli_ancient_town_sa_05', 'suzhou_tongli_ancient_town', 'Jiayin Hall', '嘉荫堂', 'Built in the early Republic of China era, Jiayin Hall was the mansion of wealthy Tongli merchant Liu Bingnan. Grand in scale, its five progressive courtyards unfold sequentially — entrance hall, sedan hall, main hall, inner hall, and rear garden — fully reproducing the spatial sequence of a great Jiangnan household. The main hall is called the (Gauze-Hat) Hall because its roof-beam structure resembles the wings of a Ming official''s gauze hat; inside, carved beams and painted pillars showcase superb craftsmanship. Jiayin Hall is laid out along the river, its main gate facing the water with a private pier on the side — a clear imprint of the merchant lifestyle of traveling by boat. The complex balances official dignity with commercial practicality, an excellent window into Tongli''s modern business-social class structure.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_05.jpg', 4),
  ('suzhou_tongli_ancient_town_sa_06', 'suzhou_tongli_ancient_town', 'Gengle Hall', '耕乐堂', 'Gengle Hall was built by Ming-era recluse Zhu Xiang, named for the ideal of "farming and studying as family tradition, joy within" — one of Tongli''s oldest surviving dwellings. Zhu Xiang refused official career all his life, finding joy in farming and reading; his residence and garden thus carry the plain, serene character of a literati-scholar. Four progressive courtyards with an attached small garden planted with osmanthus and white-bark pine, its winding paths and corridors embody the austere aesthetics of Ming literati garden-living. Compared with Tongli''s merchant mansions, Gengle Hall has few ornate carvings — instead, plain brick walls and bare wooden beams reveal their natural beauty, preserving the authentic appearance of Ming Jiangnan dwellings and providing precious physical specimens for studying Ming vernacular architecture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_06.jpg', 5),
  ('suzhou_tongli_ancient_town_sa_07', 'suzhou_tongli_ancient_town', 'Ming-Qing Street', '明清街', 'Ming-Qing Street is Tongli''s main commercial lane, roughly 300 meters long, with Ming-Qing-era shop layouts and street-front character preserved on both sides. Gloss from centuries of foot traffic still gleams on the flagstone pavement. Shops sell Su embroidery, Lake Tai pearls, Tongli''s signature pickled vegetables and "champion''s trotter" braised pork — old brands and new stalls mixing into a unique marketplace atmosphere interweaving past and present. Occasional langpeng (roofed corridors) span the street overhead, sheltering pedestrians from sun and rain — a hallmark of Jiangnan waterside commercial streets. Strolling Ming-Qing Street, the eyes take in the scroll of white walls and black tiles; the nose catches the sweet scent of pickles and lotus-root sweets; the hands feel flagstones'' warmth — senses converge into a complete Tongli memory.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_07.jpg', 6),
  ('suzhou_tongli_ancient_town_sa_08', 'suzhou_tongli_ancient_town', 'Nanyuan Tea House', '南园茶社', 'Founded in the late Qing dynasty, Nanyuan Tea House is Tongli''s most iconic traditional tea house, set along the river with two floors of wood-windowed, water-facing Suzhou-style spaces. The house features Biluochun tea and local snacks; afternoon sessions often host Suzhou pingtan performers — plucked strings ringing, melodic voices soaring, particularly moving in the waterside tea-house context. Sitting by the window with a pot of clear tea, watching boats pass on the river outside, pingtan melodies drifting into the ears, time seems to slow its pace. Nanyuan Tea House is more than a place for tea — it is a living specimen of Tongli''s waterside lifestyle, allowing visitors, in a brief pause, to touch the century-long pulse of Jiangnan tea-house culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_08.jpg', 7),
  ('suzhou_tongli_ancient_town_sa_09', 'suzhou_tongli_ancient_town', 'Chen Qubai''s Former Residence', '陈去病故居', 'Chen Qubai''s Former Residence is the old home of the renowned modern revolutionary and Nanshe (Southern Society) co-founder in Tongli. Chen Qubai (1874–1933) was a pivotal revolutionary literatus of the late Qing and early Republic, co-founding Nanshe with Liu Yazi and others, wielding literature as a weapon to advocate anti-Qing revolution and democratic ideals. The residence follows a traditional Jiangnan dwelling layout; inside, an exhibition of Chen''s life uses letters, photographs, and manuscripts to trace his journey from Tongli scholar to revolutionary pioneer. The quiet, deep old alley where the house sits contrasts sharply with Chen''s turbulent revolutionary career, revealing a truth: modern China''s upheavals often began in an unremarkable room in a small Jiangnan town.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_09.jpg', 8),
  ('suzhou_tongli_ancient_town_sa_10', 'suzhou_tongli_ancient_town', 'Luoxing Island', '罗星洲', 'Luoxing Island is a small island in Tongli Lake, reached by roughly a ten-minute boat ride from the ancient town pier. Existing structures include the Guanyin Hall, Wenchang Pavilion, and Doumu Pavilion, where Buddhist, Daoist, and Confucian faiths coexist — reflecting Jiangnan folk religion''s inclusive tradition. A small garden on the island features winding paths, lush plantings, and panoramic lake-and-hill views; gazing across the water, Tongli''s black-tiled rooftops appear faintly in the distance. Luoxing Island has been destroyed and rebuilt multiple times through war and disaster; current buildings are largely modern reconstructions, but ancient trees and ruins preserve memories of past turmoil. The boat journey — wind on the water, shimmering waves — makes arriving at the island feel like entering an otherworld paradise, the most ritual-laden segment of any Tongli visit.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tongli_ancient_town_sa_10.jpg', 9),
  ('suzhou_tuisi_garden_sa_01', 'suzhou_tuisi_garden', 'Entrance Gate', '入口宅门', 'The entrance gate faces the lanes of Tongli Ancient Town in the traditional stone-arch style, with a brick-carved lintel inscribed "Tuisi Garden." The gatehouse is constructed of finely ground grey bricks with tight mortar joints, showcasing exceptional craftsmanship. Unlike the ornate gatehouses of wealthy merchants, Tuisi Garden''s entrance deliberately pursues simplicity—befitting Ren Lansheng''s status as a demoted official returning home, and echoing the humility inherent in the garden''s name. Upon entering, a screen wall temporarily conceals the garden''s scenery, creating a spatial sequence of "suppression before revelation" that guides visitors from the bustling streets into a tranquil world.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_01.jpg', 0),
  ('suzhou_tuisi_garden_sa_02', 'suzhou_tuisi_garden', 'Sedan Chair Hall', '轿厅', 'The Sedan Chair Hall sits between the entrance gate and the main hall, an essential ceremonial transitional space in traditional Jiangnan residences. Its name derives from its original function of parking sedan chairs: arriving guests would dismount, tidy their attire, and rest briefly before being received into the main hall. The hall spans three bays with simple timber framing, modest decoration, and square-tile flooring. Wooden benches once lined both sides for attendants. Though unadorned, the Sedan Chair Hall plays a crucial role in modulating spatial rhythm—from the noise of the street to the formality of the main hall, it acts as a buffer, allowing visitors to prepare visually and psychologically, while embodying the etiquette governing host-guest relations.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_02.jpg', 1),
  ('suzhou_tuisi_garden_sa_03', 'suzhou_tuisi_garden', 'Main Hall (Hall of Sheltered Abundance)', '正厅（荫余堂）', 'Yinyu Tang is the main hall of Tuisi Garden and the most important ceremonial space in the residential quarter. The name "Yinyu" means "to shelter descendants and leave a lasting legacy," expressing Ren Lansheng''s aspirations for his family''s enduring prosperity. The hall spans three bays with a high, bright interior, fine timber construction, and drum-shaped blue-stine plinths. A plaque inscribed "Yinyu Tang" hangs at the center, flanked by couplets. The interior follows traditional arrangement—a long narrow table at the center, armchairs and side tables on either side, with calligraphy and paintings on the walls. This was the venue for receiving distinguished guests, conducting family councils, and hosting weddings and funerals. The courtyard before the hall features osmanthus and magnolia, symbolizing "abundance of gold and jade."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_03.jpg', 2),
  ('suzhou_tuisi_garden_sa_04', 'suzhou_tuisi_garden', 'Inner Residence (Wanxiang Pavilion)', '内宅（畹芗楼）', 'Wanxiang Lou is situated behind the main hall, serving as the inner residence where the owner and family conducted daily life. The name "Wanxiang" means "fragrance of orchids," alluding to Qu Yuan''s Li Sao: "I have nurtured orchids in nine fields," symbolizing the owner''s noble character. The two-story building has a ground floor for daily living and dining, with bedrooms upstairs. The interior once featured rosewood furniture, carved beds, and refined ornaments. A small courtyard before the building holds orchids and banana plants, creating a serene atmosphere. Narrow passageways and courtyard walls separate the inner residence from the public halls, forming the traditional layout of "front hall, rear quarters, inner and outer distinct," ensuring family privacy while reflecting the spatial hierarchy of Confucian propriety.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_04.jpg', 3),
  ('suzhou_tuisi_garden_sa_05', 'suzhou_tuisi_garden', 'Tuisi Thatched Hall (Hall of Retreat and Reflection)', '退思草堂', 'Tuisi Thatched Hall occupies the central position of the garden section, backing against the compound wall to the north and facing the water to the south—the heart of the entire garden. The hall''s name directly expresses the garden''s theme: "Tuisi" (Retreat and Reflection) reflects both the garden''s name and the inner state of Ren Lansheng, who sought self-examination and self-improvement after his demotion. The hall spans three bays with a single-eave gable-and-hip roof and an unadorned exterior without painted decoration; calling it a "thatched hall" heightens the sense of reclusion. A spacious terrace before the hall projects over the water, offering the finest vantage point. From here, the pond, Shuixiang Pavilion, Red Boat, Sky Bridge, and other scenes unfold in a single panorama. The interior is simply furnished with a writing desk, zither table, and armchairs, with calligraphy and paintings on the walls. The owner once read, played the zither, entertained friends, savored tea, and observed the changing seasons here.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_05.jpg', 4),
  ('suzhou_tuisi_garden_sa_06', 'suzhou_tuisi_garden', 'Shuixiang Pavilion (Water Fragrance Pavilion)', '水香榭', 'Shuixiang Pavilion stands at the southeast corner of Tuisi Garden''s central pond, a square structure half-cantilevered over the water. The name "Shuixiang" (Water Fragrance) evokes the scent of lotus blossoms drifting across the water in summer. The pavilion is light and airy, open on three sides with only one walled side featuring hexagonal latticed windows. The floor sits nearly flush with the water surface—seated inside, one feels suspended above the ripples. This is the finest spot for summer lotus viewing: the pond is planted with lotus, and in midsummer green leaves stretch to the horizon and pink blooms catch the sun, while a breeze carries the fragrance inward. Golden koi dart beneath, their reflections forming living pictures. Tuisi Garden is renowned for "hugging the water," and Shuixiang Pavilion embodies this feature at its purest—the distance between architecture and water reduced to a minimum, merging human and nature into one.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_06.jpg', 5),
  ('suzhou_tuisi_garden_sa_07', 'suzhou_tuisi_garden', 'Qin Room (Zither Room) and Mianyun Pavilion (Cloud-Resting Pavilion)', '琴房与眠云亭', 'The Qin Room and Mianyun Pavilion are located in the northwest corner of Tuisi Garden, a pair of structures that ingeniously exploit the terrain''s height difference. The Qin Room sits at the lower level—a small chamber facing the water where the owner played the zither and savored tea. The interior is secluded; across the water from Tuisi Thatched Hall, zither music could travel across the pond surface, lingering in the air. Mianyun Pavilion crowns a stone terrace above, reached by stone steps. "Mianyun" (Cloud-Resting) derives from the classical line "lying down to watch clouds rise," suggesting a restful spot as if reclining among clouds. The diminutive pavilion has walls on three sides and a window on the fourth; from here one can overlook the entire garden. The two structures—one low and one high, one at the water''s edge and one against the hill—create rich spatial layering. Gazing up from the Qin Room, Mianyun Pavilion appears as a pavilion in the clouds; looking down from the pavilion, the Qin Room seems a waterside thatched hut—motion and stillness in perfect harmony.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_07.jpg', 6),
  ('suzhou_tuisi_garden_sa_08', 'suzhou_tuisi_garden', 'Guyu Shengliang (Coolness from Rain on Water Bamboo)', '菰雨生凉', 'Guyu Shengliang stands on the western shore of the pond, a small waterside chamber built flush with the surface. "Gu" refers to water bamboo (Zizania caduciflora), a common waterside plant; "yu sheng liang" depicts the coolness that comes when rain strikes the broad leaves and a breeze ripples across the pond. The chamber opens to the water on three sides with one wall behind, its low roof and eaves nearly touching the surface. On summer days, cool breezes sweep through off the water while water bamboo sways and lotus leaves glisten, instantly dispelling the heat. In gentle rain, droplets striking the leaves and water create a crystalline murmur—a natural symphony that deepens the sense of coolness. A calligraphic plaque inscribed "Gu Yu Sheng Liang" hangs within. This scene fuses sight, sound, and touch—watching green bamboo sway, hearing rain on rippling water, feeling cool wind on the skin—representing the ultimate expression of Tuisi Garden''s art of atmosphere and a paradigm of the Chinese garden principle of "scene evoking emotion, emotion entering realm."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_08.jpg', 7),
  ('suzhou_tuisi_garden_sa_09', 'suzhou_tuisi_garden', 'Sky Bridge and Xintai (Xin Terrace)', '天桥与辛台', 'Sky Bridge and Xintai are located in the northeast of Tuisi Garden, an ingenious three-dimensional architectural composition. Sky Bridge is a covered corridor built against the wall, spanning above the pond to connect Tuisi Thatched Hall with Xintai. The bridge is slender with low railings; walking across it feels like skimming over the water, offering views of koi and lotus below. Xintai stands at the bridge''s northern end—a small square pavilion raised above the surrounding level, where the owner read and reflected. The character "Xin" connotes "hardship" and "diligence," echoing the garden''s theme of "retreating to reflect on one''s faults," reminding the owner to persevere even in reclusion. The bridge and pavilion—one horizontal and one vertical, one in motion and one still—generate rich spatial layering within the compact garden. From the bridge, Xintai appears as a pavilion atop a mountain; from Xintai, the bridge resembles a rainbow skimming the water, lending the small garden the feel of vast mountains and forests within a limited space.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_09.jpg', 8),
  ('suzhou_tuisi_garden_sa_10', 'suzhou_tuisi_garden', 'Naohong Yige (Red Boat) and Nine-Turn Winding Corridor', '闹红一舸与九曲回廊', 'Naohong Yige and the Nine-Turn Corridor are situated around Tuisi Garden''s central pond, forming the garden''s most picturesque composition. "Naohong Yige" is a stone boat-shaped pavilion with its bow pointing toward the center of the pond, as if a skiff were about to glide into a lotus thicket. "Naohong" (Bustling Red) derives from the image of "a touch of red among ten thousand greens," depicting the lively scene of red lotus blooming in a summer pond. The boat is built of stone with a small cabin above where one can sit and enjoy the water views. The Nine-Turn Corridor winds along the eastern shore of the pond, connecting Tuisi Thatched Hall with various scenic spots. The corridor follows the terrain and shoreline through nine bends, hence its name. Its walls are embedded with calligraphic stone tablets and latticed windows, offering ever-changing views at every step. Walking through the corridor, one moment you lean over the water to watch fish, the next you peer through a window at a framed vista—a richly varied spatial experience. The "movement" of the boat and the "winding" of the corridor complement each other, generating boundless pleasure of exploration within a finite space.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_tuisi_garden_sa_10.jpg', 9),
  ('suzhou_master_of_nets_garden_sa_01', 'suzhou_master_of_nets_garden', 'Entrance Gate', '入口大门', 'The entrance gate of Wangshi Yuan is located at No. 11, Kuojia Tou Lane, nestled among residential alleyways in the southeastern corner of Suzhou''s old city. The gatehouse follows traditional Jiangnan residential style, with a grey-brick doorframe, black-lacquered wooden doors, and a plaque reading "Wangshi Yuan" above the lintel. The narrow lane approaching the gate is lined with white walls and grey-tiled eaves, giving no hint that a UNESCO World Heritage garden lies at its end. This "hidden within the city" setting is precisely the garden''s defining characteristic—the owner sought not street-facing grandeur, but a tranquil retreat within the bustling city. Pushing open the door reveals the Sedan Chair Hall, offering a glimpse of the garden within, guiding visitors from the mundane alley into a refined garden realm. The interplay of compression and release in spatial design showcases the masterful vision of the garden''s creator.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_01.jpg', 0),
  ('suzhou_master_of_nets_garden_sa_02', 'suzhou_master_of_nets_garden', 'Sedan Chair Hall', '轿厅', 'The Sedan Chair Hall is the first building in the residential section of Wangshi Yuan and the first interior space visitors enter. The hall spans three bays with a simple, open beam-frame structure. It was originally used for parking sedan chairs: guests would dismount here, and after a servant announced them to the master, they would be received into the inner hall. A plaque inscribed by a Qing Dynasty scholar hangs at the center, flanked by couplets whose texts often relate to fishing and reclusion, echoing the garden''s name "Master of the Nets." The hall contains a large wall mirror and a marble screen—the mirror reflects the courtyard scene behind, creating an illusion of extended space within the compact hall. This is a classic "borrowed scenery" technique in Suzhou gardens. Though merely a transitional space, the Sedan Chair Hall already reveals the owner''s cultural refinement and design philosophy through these carefully curated elements.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_02.jpg', 1),
  ('suzhou_master_of_nets_garden_sa_03', 'suzhou_master_of_nets_garden', 'Wanjuan Hall (Hall of Ten Thousand Scrolls)', '万卷堂', 'Wanjuan Hall is the main hall of Wangshi Yuan''s residential quarter and the garden''s most important ceremonial building. The name "Wanjuan Tang" (Hall of Ten Thousand Scrolls) traces back to the Southern Song Dynasty, when Shi Zhengzhi, Vice Minister of Personnel, built a garden here to house his vast book collection—the name embodying the Chinese literati ideal of "reading ten thousand scrolls." When Song Zongyuan rebuilt the garden during the Qianlong reign of the Qing Dynasty, he retained the name in tribute to his predecessor. The hall spans five bays with a lofty, imposing interior, robust timber columns, and blue-stone basin-shaped plinths. A plaque reading "Wanjuan Tang" hangs at the center, featuring calligraphy attributed to Ming Dynasty master Wen Zhengming. The interior follows traditional arrangement: a long narrow table at center, armchairs on either side, and celebrated paintings and calligraphy on the walls. The courtyard before the hall features golden osmanthus and white magnolia, symbolizing "abundance of gold and jade." This was where the owner received distinguished guests, hosted family banquets, and displayed his cultural refinement.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_03.jpg', 2),
  ('suzhou_master_of_nets_garden_sa_04', 'suzhou_master_of_nets_garden', 'Xiexiu Tower (Gathering Elegance Tower)', '撷秀楼', 'Xiexiu Tower stands directly north of Wanjuan Hall, serving as the inner residence of Wangshi Yuan where the owner and family conducted daily life. "Xiexiu" means "gathering elegance," derived from the poetry of Xie Lingyun of the Southern Dynasties, expressing the owner''s aspiration for a refined life. The two-story building has a ground floor for living and dining, with bedrooms and a study upstairs. The upper floor features a corridor and windows that open onto views of Rosy Cloud Pool and the garden''s pavilions. The interior once contained rosewood furniture, carved railings, and exquisite latticed windows, all demonstrating superb craftsmanship. A small sky-well connects Xiexiu Tower to Wanjuan Hall, with a planted flower bed featuring camellia and nandina, providing year-round interest. The transition from Wanjuan Hall to Xiexiu Tower marks a shift from public ceremonial space to private domestic space, embodying the traditional residential layout of "front hall, rear tower, inner and outer distinct," while showcasing the refinement of a wealthy Suzhou household''s daily life.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_04.jpg', 3),
  ('suzhou_master_of_nets_garden_sa_05', 'suzhou_master_of_nets_garden', 'Tiyun Room (Cloud-Stepping Room)', '梯云室', 'Tiyun Room is located in the northwest of Wangshi Yuan, serving as the owner''s study. "Tiyun" (Cloud-Stepping) derives from a Tang Dynasty tale of Zhou Sheng "climbing clouds to fetch the moon," metaphorically suggesting ascending to lofty heights in pursuit of elevated ideals. The most brilliant feature of this room is its means of access: rather than a conventional wooden staircase, a pathway of Taihu limestone rocks is stacked into a miniature mountain path. One must ascend along the rockery to reach the second-floor study, as if walking on clouds—hence "Tiyun." The rockery serves dual purpose as both staircase and landscape feature, a masterstroke of ingenuity. The interior was once furnished with a writing desk, bookshelves, and the Four Treasures of the Study, in a serene setting. Windows reveal rockeries and verdant bamboo outside, creating the atmosphere of "a study hidden in the mountains." Tiyun Room''s design exemplifies the Suzhou garden principle of "adapting to the terrain and borrowing cleverly," perfectly uniting practical function with aesthetic delight—a classic case of "function as art" in garden architecture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_05.jpg', 4),
  ('suzhou_master_of_nets_garden_sa_06', 'suzhou_master_of_nets_garden', 'Kansong Duhua Veranda (Pine-Viewing and Painting-Reading Veranda)', '看松读画轩', 'Kansong Duhua Veranda stands on the western shore of Rosy Cloud Pool, one of the most literati-spirited buildings in Wangshi Yuan. The name "Kansong Duhua" (Viewing Pines and Reading Paintings) identifies the two refined pursuits associated with this space: admiring ancient pines and contemplating painted landscapes. The veranda has three bays facing south toward the water, with a seated railing at the front for both sitting and viewing. In the courtyard before the veranda grows a Buddhist pine (Podocarpus) estimated to be several centuries old, its weathered branches and ancient silhouette set against Taihu rocks, forming a natural "pine and rock painting." Seated inside, the owner could appreciate the vigor of the pine and the mood of paintings, with nature and art intermingling seamlessly. The interior once held a writing desk and hanging paintings, with delicately patterned latticed windows framing views like picture frames. Looking out from the veranda, Rosy Cloud Pool, the Moon-Arriving Pavilion, and Zhuoying Water Pavilion layer upon one another like an unrolling landscape scroll. This veranda exemplifies the Suzhou garden aesthetic of "still contemplation"—not wandering through scenery, but sitting peacefully and letting the landscape come to you.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_06.jpg', 5),
  ('suzhou_master_of_nets_garden_sa_07', 'suzhou_master_of_nets_garden', 'Dianchun Yi (Late Spring Cabin)', '殿春簃', 'Dianchun Yi is located in the northwest corner of Wangshi Yuan, a self-contained courtyard of its own. "Dianchun" refers to late spring—herbaceous peonies, the last flowers to bloom in spring, were called "dianchun flowers," and since peonies were originally planted here, the name "Dianchun Yi" was chosen. "Yi" means a small chamber beside a main building. Though the courtyard covers barely a quarter-acre, it integrates architecture, rockery, plantings, and a spring—a "garden within a garden." The main room is a three-bay study with refined furnishings including a writing desk, zither table, and antiquities. Before the study stands a half-pavilion named Lengquan Ting (Cold Spring Pavilion), beside Hanbi Spring, whose crystal-clear water never runs dry. Taihu stone peaks in the courtyard are exquisitely perforated, complemented by peonies, plum trees, and bamboo. In 1980, the Metropolitan Museum of Art in New York created the Astor Court (Ming Studio) based on Dianchun Yi, marking a milestone in the global journey of Chinese classical gardens. Dianchun Yi thus became a celebrated chapter in the history of Sino-American cultural exchange.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_07.jpg', 6),
  ('suzhou_master_of_nets_garden_sa_08', 'suzhou_master_of_nets_garden', 'Yuedao Fenglai Pavilion (Moon-Arriving and Wind-Coming Pavilion)', '月到风来亭', 'Yuedao Fenglai Pavilion stands at the center of Rosy Cloud Pool''s western shore, surrounded by water on three sides—the core structure of Wangshi Yuan''s waterscape. The name derives from a line by Song Dynasty poet Shao Yong: "When the moon reaches the heart of heaven, when the wind comes across the water''s surface"—a vision of transcendent beauty: moonlight at zenith bathes all in radiance, and wind on water ripples into endless patterns. The square pavilion has a gable-and-hip roof, open on three sides with one wall. A "beauty''s resting" railing faces the water; seated here, the pool''s surface mirrors the world. This is the garden''s premier moon-viewing spot—on Mid-Autumn night, the bright moon rises in the east and reflects into the pool, one moon above and one below shimmering in tandem, the ultimate Suzhou garden moon-viewing experience. A large mirror hangs inside the pavilion, reflecting the pavilions across the water—virtual and real intertwining, giving the compact pool infinite depth. The pavilion masterfully integrates four elements—moon, wind, water, and mirror—exemplifying the highest ideal of Chinese gardens: "though made by human hands, it seems created by nature itself."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_08.jpg', 7),
  ('suzhou_master_of_nets_garden_sa_09', 'suzhou_master_of_nets_garden', 'Zhuoying Water Pavilion (Tassel-Washing Water Pavilion)', '濯缨水阁', 'Zhuoying Water Pavilion stands on the southern shore of Rosy Cloud Pool, a water pavilion built flush with the surface. "Zhuoying" (washing tassels) derives from the Chu Ci (Songs of Chu) "Yu Fu" chapter: "When the waters of Canglang are clear, I can wash my hat-strings." "Ying" refers to the strings of an official''s cap; "washing the tassels" metaphorically means cleansing oneself of official life and retreating to nature. This naming perfectly echoes Wangshi Yuan''s theme of "fisherman''s reclusion." The pavilion spans three bays with a gable-and-hip roof, open on all sides, supported on stone columns above the water. Inside are stone tables and stools; on summer days, cool breezes sweep through off the pool, dispelling all heat. Looking north from the pavilion, Yuedao Fenglai Pavilion and Kansong Duhua Veranda face each other across the water, reflected in the pool like a symmetrical ink painting. The name plaque was inscribed by a Qing Dynasty scholar, with couplets relating to the themes of fishing and the Canglang River. Zhuoying Water Pavilion uses literary allusion as its inner core and waterscape as its outer expression, seamlessly fusing poetic, pictorial, and garden meaning into one.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_09.jpg', 8),
  ('suzhou_master_of_nets_garden_sa_10', 'suzhou_master_of_nets_garden', 'Zhuwai Yizhi Veranda (A Single Branch Beyond Bamboo Veranda)', '竹外一枝轩', 'Zhuwai Yizhi Veranda is located at the northeast corner of Rosy Cloud Pool, a narrow, elongated pavilion built along the water. "Zhuwai Yizhi" (A Single Branch Beyond Bamboo) derives from Su Shi''s poem "He Qin Taixu Meihua": "A single branch slanting beyond bamboo is all the more lovely," originally describing how a plum branch extending beyond a bamboo thicket embodies elegant restraint. The name identifies both the plantings outside the window—bamboo and plum—and the viewing experience itself, which resembles contemplating a literati painting: spare yet resonant. The veranda has three bays running north-south, facing the water to the west and backed by a wall to the east. The western side features a full run of tall latticed windows, each frame like a picture frame capturing the pool scenery. Outside, a few stalks of bamboo and a single plum tree grow; in winter, when a plum branch extends beyond the bamboo, the poem''s imagery comes alive. The narrow interior has a seated railing and small table, ideal for sitting alone with tea and quietly observing the water. Looking out, Yuedao Fenglai Pavilion and Zhuoying Water Pavilion across Rosy Cloud Pool appear like a landscape painting, virtual and real interplaying. This veranda achieves much with little, sees the large within the small—a vivid embodiment of the Suzhou garden philosophy of "a mustard seed holding Mount Sumeru."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_master_of_nets_garden_sa_10.jpg', 9),
  ('suzhou_yi_garden_sa_01', 'suzhou_yi_garden', 'Entrance Gate', '入口宅门', 'The entrance to Yipu Garden is deliberately inconspicuous, tucked away at the far end of Wenya Lane — a narrow, winding alleyway in Suzhou''s old city. This "hidden within the city" approach is characteristic of Suzhou''s literati gardens, which favor understatement over grandeur. The gate itself is a traditional stone-framed doorway with grey brick and dark tiles, virtually indistinguishable from neighboring residences. First-time visitors can easily walk past without realizing that a UNESCO World Heritage garden lies within. Stepping through the gate, the noise of the city falls away instantly, replaced by a serene courtyard — a spatial transition from bustle to tranquility that is Yipu''s first gift to every guest.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_01.jpg', 0),
  ('suzhou_yi_garden_sa_02', 'suzhou_yi_garden', 'Shilun Hall', '世纶堂', 'Shilun Hall is the first main hall along Yipu Garden''s central axis, facing south with three bays. Its architectural style is plain and dignified — no painted beams, no gilded columns — preserving the hallmark simplicity of Ming Dynasty construction. The name "Shilun" derives from "," reflecting the owner''s aspiration to engage meaningfully with worldly affairs. A stone-paved courtyard precedes the hall, graced by an old tree whose dappled shade plays against whitewashed walls and dark tiles. Originally adorned with calligraphic plaques, the hall served as a gathering place for receiving guests, sipping tea, and scholarly discussion. The intimate scale and absence of ostentation embody the Ming-era literati ideal: "seek not grandeur, but refinement and cleanliness."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_02.jpg', 1),
  ('suzhou_yi_garden_sa_03', 'suzhou_yi_garden', 'Donglai Thatched Cottage', '东莱草堂', 'Situated behind Shilun Hall, Donglai Thatched Cottage is the second building along the garden''s central axis. The name "Donglai" is believed to reference the garden owner''s ancestral homeland, carrying a note of nostalgia, while "thatched cottage" () is a humble term Chinese scholars have long favored to signal a life of reclusion, free from worldly ambition. The interior is simply furnished — a writing desk, calligraphy brushes, and inkstones neatly arranged. Light filters through latticed windows where bamboo shadows sway, creating a serene reading environment. This is where the garden owner spent his days reading, entertaining close friends, and composing poetry. From the cottage window, the central pond and rockery unfold in full view — a perfect demonstration of the Suzhou gardening principle of "seeing the universe within a small space."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_03.jpg', 2),
  ('suzhou_yi_garden_sa_04', 'suzhou_yi_garden', 'Sishi Pavilion', '思嗜轩', 'Sishi Pavilion sits on the southern bank of Yipu''s central pond — a delicately proportioned waterside structure. The name "Sishi" means "to reflect upon one''s passions and loves," revealing the garden owner''s devotion to a particular way of life and spiritual pursuit. The pavilion opens directly onto the water, offering sweeping views of Yanguang Pavilion, rockeries, and waterside towers to the north — making it one of the finest vantage points in the garden. Inside, a single table and chair suffice; the minimalism perfectly suits the literati ideal of solitary contemplation. On misty mornings or golden-hour evenings, when warm light bathes the whitewashed walls, this corner becomes the most poetic spot in the entire garden — a place to brew tea, open a book, listen to leaping fish, and watch blossoms unfold and fall.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_04.jpg', 3),
  ('suzhou_yi_garden_sa_05', 'suzhou_yi_garden', 'Ruyu Pool', '乳鱼池', 'Ruyu Pool is the heart of Yipu Garden''s landscape — a central pond of just over one mu (roughly 670 square meters) that, though modest in size, offers richly layered views. The name "Ruyu" (literally "nursling fish") is poetically drawn from a classical verse describing tiny fish moving across the water''s surface like freshly formed ice marks — a delicate, almost imperceptible animation. The water is clear, with koi gliding lazily beneath the surface. The pond''s irregular shoreline is edged with yellow stones laid in a naturalistic style. To the south, Sishi Pavilion rises at the water''s edge; to the north, Yanguang Pavilion stretches along the shore; rockeries and towers frame the east and west — together forming the classic garden layout of "water at the center, architecture encircling." Standing at the pond''s edge, sky and clouds reflect in the water, dissolving the boundary between reality and reflection, and the world beyond seems to vanish.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_05.jpg', 4),
  ('suzhou_yi_garden_sa_06', 'suzhou_yi_garden', 'Yanguang Pavilion', '延光阁', 'Yanguang Pavilion is Yipu Garden''s most iconic structure, perched on the northern shore of Ruyu Pool. Five bays wide with a single-eave gable roof, it is one of the largest waterside pavilions in all of Suzhou''s classical gardens. The name "Yanguang" means "extending light" — drawing sunlight and scenery into the interior. True to its name, the building opens on three sides to the water, with latticed windows on the south facade that, when fully opened, frame the entire garden panorama as if the whole landscape were gathered into one''s embrace. The interior is paved with square tiles and simply furnished; today it serves as a tea room where visitors can rest and sip tea. Seated inside with a cup of Biluochun green tea, watching the pond''s reflections tremble in the breeze and listening to raindrops tap the eaves, one truly understands the ancient wisdom that "a room need not be grand to be elegant." Yanguang Pavilion is also the finest vantage point for the garden''s seasonal pageant: tender green in spring, lotus breezes in summer, crimson leaves in autumn, and silent snow in winter.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_06.jpg', 5),
  ('suzhou_yi_garden_sa_07', 'suzhou_yi_garden', 'Chaoshuang Pavilion', '朝爽亭', 'Chaoshuang Pavilion crowns the summit of the rockery on the eastern side of Ruyu Pool — a small, open-sided square pavilion. The name "Chaoshuang" is drawn from a classical phrase meaning "the crisp, refreshing air that comes with morning," signaling that this is the place to ascend, gaze afar, and breathe in the pure mountain-like breeze. Though modest in size, the pavilion is the highest point in the garden. Ascending the winding stone steps and pausing at the top, visitors enjoy a sweeping panorama: the pond, architecture, and plantings of the entire garden spread below like a three-dimensional landscape painting — a masterful demonstration of "seeing the vast within the small." A couplet hangs on the pavilion columns; the roof is simple and unornamented, in keeping with the garden''s unified aesthetic of restrained antiquity. The finest moments to climb are at dawn and dusk: in the early morning, mist clings to the garden like ink wash on paper; at sunset, golden light carpets the water and the pavilion''s silhouette turns into a painting.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_07.jpg', 6),
  ('suzhou_yi_garden_sa_08', 'suzhou_yi_garden', 'Bilang Pavilion', '碧浪亭', 'Bilang Pavilion occupies the southeastern corner of Ruyu Pool — a slender hexagonal structure with gracefully proportioned eaves. The name "Bilang" (literally "emerald waves") evokes the green ripples that shimmer across the pond when a breeze passes over, so that the pavilion''s name is itself a living picture. Three sides of the pavilion face the water; the fourth connects to the shore. Standing inside, one can look down to see the clear, shallow pond and fish darting among lotus leaves; looking up, Yanguang Pavilion''s flying eaves and Chaoshuang Pavilion atop the rockery create a layered composition of near and far, high and low. Old trees grow beside the pavilion, their branches dipping into the water, swaying gently, mirrored in the pond below. This is the garden''s best spot for simply "sitting still" — not rushing to the next site, not fumbling with a camera, just quietly feeling the breeze and listening to birdsong, experiencing the complete aesthetic of Suzhou gardens where one can roam, dwell, and sit in equal measure.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_08.jpg', 7),
  ('suzhou_yi_garden_sa_09', 'suzhou_yi_garden', 'Qinlu Hermitage', '芹庐', 'Qinlu Hermitage lies in the western section of Yipu Garden — a small courtyard set apart from the main scenic area, accessible only through a winding corridor, making it the most secluded corner of the entire garden. The character "" (celery/water dropwort) comes from the Book of Odes: "By the joyful waters of Pan, I gather the water celery." Since ancient times, "offering celery" has been a scholar''s humble metaphor — the gift may be meager, but the sincerity is genuine. Naming this retreat "Qinlu" reveals the garden owner''s contentment with simplicity and his celebration of the unadorned. Within the courtyard stand a few stalks of bamboo, an old plum tree, and one or two scholar''s rocks set against whitewashed walls — a natural literati painting. Though tiny, the courtyard embodies the Buddhist principle of "a mustard seed holding Mount Sumeru" — the universe within a square inch. This was the owner''s retreat for reading and meditation, and even today, far from the flow of visitors in the main garden, it retains the purest breath of antiquity.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_09.jpg', 8),
  ('suzhou_yi_garden_sa_10', 'suzhou_yi_garden', 'Boya Hall', '博雅堂', 'Boya Hall stands at the far northern end of Yipu Garden''s architectural sequence — the deepest hall in the entire compound. The name "Boya" means "broadly learned and upright in heart," reflecting the Confucian ideal of scholarly depth paired with moral integrity. A courtyard precedes the hall, planted with banana palms and heavenly bamboo that change character with each season. The interior is spacious and bright; it originally housed the owner''s collection of rare books, calligraphy, paintings, and bronze-and-stone antiquities, and served as a venue for scholarly gatherings and the connoisseurship of art. The architectural style continues the garden''s signature plainness — unpainted beams, whitewashed walls, square-tile floors — relying on the natural grain of the wood and the purity of line for its quiet authority. As the final stop on the visitor''s route, Boya Hall serves as the coda to a well-crafted book: looking back along the path just walked, the pond, pavilions, rockeries, and flora rise in sequence, leaving a lingering aftertaste and a deepened reverence for this "ultimate expression of the small garden."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_yi_garden_sa_10.jpg', 9),
  ('suzhou_zhouzhuang_ancient_town_sa_01', 'suzhou_zhouzhuang_ancient_town', 'Ancient Stage', '古戏台', 'The Ancient Stage is located near the entrance of Zhouzhuang and is a classic example of a traditional Jiangnan theatrical stage. First built during the Qing Dynasty and later restored, it retains its original timber-frame structure. The stage faces north, with its back to the water. The front stage features a gable-and-hip roof with upturned flying eaves, while the backstage dressing area is separated from the front by a wooden screen. The stone-pillar foundation raises the stage about one meter above ground, allowing viewing from all four sides. Wood carvings adorn the beams, brackets, and lintels — depicting opera scenes and auspicious motifs with exquisite craftsmanship, making this stage an important artifact for the study of Jiangnan folk carving art. In centuries past, opera troupes were invited to perform Kunqu, Yueju, and Xiju during festivals, with townsfolk gathering at the water''s edge to watch — a cherished memory of Zhouzhuang''s cultural life. Today, the stage still hosts regular performances of Kunqu and other traditional operas, open to all visitors at no additional charge.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_01.jpg', 0),
  ('suzhou_zhouzhuang_ancient_town_sa_02', 'suzhou_zhouzhuang_ancient_town', 'Twin Bridges', '双桥', 'The Twin Bridges — Shide Bridge and Yong''an Bridge — are so named because they intersect at right angles, one arched and one straight, together resembling an ancient Chinese key. Hence they are also called "Key Bridge" (). Shide Bridge is a stone arch bridge built during the Wanli era of the Ming Dynasty (1573–1620); Yong''an Bridge, a stone beam bridge, dates from the same period. The two bridges span the confluence of Yinzi Stream and the North-South River. Water murmurs below; whitewashed houses with dark-tiled roofs line the banks, their reflections creating a natural ink-wash painting. In 1984, the renowned painter Chen Yifei created the oil painting "Memory of Hometown" featuring the Twin Bridges. Recommended by Armand Hammer, the painting was selected by the United Nations for a first-day cover — launching Zhouzhuang onto the world stage and making the Twin Bridges the most recognizable cultural symbol of Jiangnan water towns. At dawn, when mist rises from the river, or at dusk, when golden light floods the scene, the Twin Bridges reveal their most breathtaking beauty — an unmissable subject for photographers.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_02.jpg', 1),
  ('suzhou_zhouzhuang_ancient_town_sa_03', 'suzhou_zhouzhuang_ancient_town', 'Shen Hall', '沈厅', 'Shen Hall is the largest private residence in Zhouzhuang, built in 1742 (the seventh year of the Qianlong reign) by Shen Benren, a descendant of the legendary "richest man in Jiangnan" — Shen Wansan. Covering over 2,000 square meters with more than 100 rooms, the complex faces west and comprises seven courtyards with five gateways along a central axis — front hall, main hall, rear hall, and more — flanked by side chambers and connecting corridors in a rigorously ordered layout. The main hall, "Songmao Hall," spans five bays with massive beams and columns. Its nanmu-wood carved floor-to-ceiling latticed windows are works of art, and the brick carvings on the gateways — depicting scenes from "Dream of the Red Chamber" and "Romance of the Western Chamber" — are masterpieces of Jiangnan residential brick sculpture. The layout reflects the classic merchant-family pattern of "shop in front, residence in the middle, garden behind," offering a vital window into the rise and fall of Ming-Qing commercial dynasties. Today, the hall houses an exhibition on Shen Wansan''s life, telling the dramatic story of this legendary merchant.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_03.jpg', 2),
  ('suzhou_zhouzhuang_ancient_town_sa_04', 'suzhou_zhouzhuang_ancient_town', 'Zhang Hall', '张厅', 'Zhang Hall, originally named "Yuyan Hall," was built during the Zhengtong era of the Ming Dynasty (1436–1449) by descendants of Xu Mengqing, brother of the Prince of Zhongshan, Xu Da. It later passed to the Zhang family, hence its current name. The residence faces west, with six courtyards, over 1,000 square meters of floor area, and more than 70 rooms. Its most distinctive feature is that the Mingjing River — a canal running through the town — flows directly through the courtyard, complete with a private mooring where boats could dock. This spatial arrangement, in which "sedans enter through the front gate and boats pass through the house," is one of the most representative layouts of Jiangnan water-town residences. Inside, nanmu-wood columns and intricately carved window lattices remain well preserved. The rear courtyard contains a miniature water garden with banana palms and bamboo — combining the dignity of an official''s mansion with the warmth and vitality of a riverside home. Visiting Zhang Hall is the best way to understand the centuries-old wisdom of "living by the water."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_04.jpg', 3),
  ('suzhou_zhouzhuang_ancient_town_sa_05', 'suzhou_zhouzhuang_ancient_town', 'Fu''an Bridge', '富安桥', 'First built during the Zhizheng era of the Yuan Dynasty (1341–1368), Fu''an Bridge was funded by Shen Wansi, the younger brother of the legendary merchant Shen Wansan. After multiple restorations, it is one of the oldest surviving stone arch bridges in Zhouzhuang. The bridge spans the North-South River in a single arch, about 17 meters long, with a gently arched deck paved in granite slabs. Its most distinctive feature is the four corner buildings — "bridge towers" — that rise from the bridge''s four corners, creating the rare architectural form of "bridge and building as one." The bridge deck remains a thoroughfare, while the towers house shops and teahouses — a design that fuses transportation and commerce, exceedingly rare among Jiangnan water-town bridges. The towers'' upturned eaves reflect in the water; from a distance, they look like pavilions floating on the river. Legend has it that Shen Wansan ran a small stall near the bridge before his fortune was made, and "Fu''an" (literally "wealth and peace") commemorates his rise. Standing on the bridge, one sees the staggered riverside dwellings along both banks, with awning boats gliding slowly beneath the arch — a quintessential water-town tableau.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_05.jpg', 4),
  ('suzhou_zhouzhuang_ancient_town_sa_06', 'suzhou_zhouzhuang_ancient_town', 'Milou (Labyrinth Tower)', '迷楼', 'Milou was originally a small riverside tavern called "Deji Wine House," built in the late Qing or early Republican era — a modest two-story building by the water. In 1920, poets of the Southern Society (), including Liu Yazi, Ye Chucang, and Wang Dajue, gathered here to drink and compose poetry. Ye Chucang later published his poems from this gathering as the collection "Milou Ji" (Labyrinth Tower Collection), and the tavern became widely known — henceforth called "Milou." The character "" (lost/bewitched) conveys both the intoxication of wine and the poets'' bewilderment and lament over the turbulent times. The interior is small, with a steep, narrow wooden staircase; the second floor has windows overlooking the canal. Today, Milou displays reproductions of the Southern Society poets'' biographies and handwritten works, recreating the spiritual world of early Republican-era Jiangnan literati who expressed their patriotism and sorrow through wine and verse. Though not the largest attraction in Zhouzhuang, its literary depth makes it a must-visit for lovers of literature and history.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_06.jpg', 5),
  ('suzhou_zhouzhuang_ancient_town_sa_07', 'suzhou_zhouzhuang_ancient_town', 'Zhouzhuang Museum', '周庄博物馆', 'Zhouzhuang Museum is located within the historic Zhu family residence — a comprehensive museum dedicated to the local history and culture of Zhouzhuang. The building itself is a typical Jiangnan residence with a Qing Dynasty layout: whitewashed walls, dark tiles, courtyards, and sky-wells. Multiple exhibition halls cover the town''s founding, commercial development, folk customs, and notable figures. The collection includes precious Ming and Qing-era contracts, land deeds, merchant account books, ancient coins, and folk implements — with the richest materials relating to Shen Wansan and traditional water-town daily life. Models, photographs, and multimedia displays vividly illustrate how Zhouzhuang grew "from water into a town, and from commerce into prosperity." Visiting the museum is the ideal starting point for understanding Zhouzhuang: build a historical framework here first, then explore the town''s sights — and the experience will be transformed.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_07.jpg', 6),
  ('suzhou_zhouzhuang_ancient_town_sa_08', 'suzhou_zhouzhuang_ancient_town', 'Guailou (Strange Tower)', '怪楼', 'Guailou is a distinctive attraction within Zhouzhuang themed around optical illusions and interactive experiences. Standing three stories tall, its exterior already differs subtly from the surrounding traditional buildings, hinting at the novelty within. Multiple themed rooms inside use principles of optics, geometry, and perspective to create astonishing visual effects: one room has a sloping floor with level walls, producing a sensation of weightlessness; another uses mirrors and lighting to simulate infinite space; yet another employs 3D murals that make visitors feel they have stepped into a painting. Each space encourages hands-on experience and creative photography, making it tremendous fun. Guailou injects a splash of modern artistic vibrancy into this thousand-year-old town, where tradition and creativity collide to delightful effect. It is especially popular with younger visitors and families — a lighthearted counterpoint to the town''s historical sights.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_08.jpg', 7),
  ('suzhou_zhouzhuang_ancient_town_sa_09', 'suzhou_zhouzhuang_ancient_town', 'Zhenfeng Bridge', '贞丰桥', 'Zhenfeng Bridge is a single-arch stone bridge spanning the Zhongshi River. Its date of original construction is unknown; the current structure dates from a Qing Dynasty rebuilding. "Zhenfeng" derives from Zhouzhuang''s ancient name — "Zhenfeng Li." During the Yuanyou era of the Song Dynasty (1086), a local official named Zhou Digonglang established a manor here and donated farmland to Quanfu Temple. The grateful residents renamed the place "Zhouzhuang" in his honor. The name "Zhenfeng Bridge" is a living fossil of this thousand-year-old renaming. The bridge is modest in length, with an elegant arch, plain stone railings, and stone steps at both ends. Riverside houses rise directly from the water; willows dip their branches toward the river; an occasional sculling boat drifts past with a rhythmic creak of the oar, complementing the ancient bridge''s quiet charm. Fewer tourists gather here than at the Twin Bridges or Fu''an Bridge, making Zhenfeng Bridge a serene spot to sit, slow down, and savor the unhurried rhythms of water-town life. A teahouse once stood by the bridge, and it is said that Southern Society poets gathered here to compose verse, adding a literary luster to its stones.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_09.jpg', 8),
  ('suzhou_zhouzhuang_ancient_town_sa_10', 'suzhou_zhouzhuang_ancient_town', 'Quanfu Temple', '全福讲寺', 'Quanfu Temple stands on the shore of Lake Bianxian, south of Zhouzhuang Old Town. Founded in 1086 during the Song Dynasty''s Yuanyou era — built on land donated by Zhou Digonglang — it is the oldest Buddhist temple in Zhouzhuang. The temple rises directly from the lake, with its main halls standing at the water''s edge. From a distance, the halls and pavilions appear to float upon the water, earning it the name "Buddhist Kingdom on Water" (). The complex faces south, with a gate, main hall, and scripture repository along its central axis. The architecture is grand and solemn — golden walls, dark tiles, layered flying eaves — striking against the blue water and sky. The temple once housed a Song Dynasty bronze bell whose peal carried for miles; "Quanfu Dawn Bell" was one of the historic Eight Scenes of Zhouzhuang. Destroyed and rebuilt multiple times, the current structures are modern reconstructions that nonetheless preserve the layout and dignity of a traditional Buddhist monastery. At dawn, the temple bell rings across the misty lake, its sound blending with the water''s shimmer to instill a deep tranquility. From the upper floors of the scripture repository, one looks out over the vast expanse of Lake Bianxian, with Zhouzhuang''s water-town panorama spread below — one of the few elevated vantage points in the town.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_zhouzhuang_ancient_town_sa_10.jpg', 9),
  ('suzhou_humble_administrators_garden_sa_01', 'suzhou_humble_administrators_garden', 'Lanxue Hall (Hall of Orchid and Snow)', '兰雪堂', '，，。"，"，、。《》，。，，"，"，，。 / Lanxue Hall is the main entrance hall of the Humble Administrator''s Garden, a three-bay structure with a rigid gable roof. Its name comes from Li Bai''s verse "Standing alone between heaven and earth, a fresh breeze scatters orchids and snow," reflecting the garden owner''s lofty aspirations and integrity. In front of the hall stands a large lacquer carving of the full garden panorama. Inside, the decor is restrained and refined, with a painting of pines and bamboo hanging in the central hall and a couplet extolling both natural beauty and scholarly pursuits — setting the tone for the entire literati garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_01.jpg', 0),
  ('suzhou_humble_administrators_garden_sa_02', 'suzhou_humble_administrators_garden', 'Yuanxiang Hall (Hall of Distant Fragrance)', '远香堂', '，，。《》""，。，，——，，，，，""""。 / Yuanxiang Hall is the architectural centerpiece of the garden''s middle section, a three-bay hall raised on a bluestone platform. Its name draws from Zhou Dunyi''s famous essay "On Loving the Lotus" — "the farther the fragrance travels, the purer it becomes" — subtly expressing the owner''s self-identification with the lotus''s noble character. With floor-to-ceiling latticed windows on all four sides and no solid walls, the hall offers uninterrupted views in every direction: northward to the Snow-Fragrant Cloud-Like Pavilion, southward to the yellowstone rockery and magnolia, westward to the Lotus Breeze Pavilion, and eastward to the Embroidered Silk Pavilion. It is a masterclass in the Chinese garden techniques of "framed views" and "borrowed scenery."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_02.jpg', 1),
  ('suzhou_humble_administrators_garden_sa_03', 'suzhou_humble_administrators_garden', 'Xiangzhou (Fragrant Isle)', '香洲', '，、、、，，，，。。""，""，，。""，。 / Xiangzhou is one of the garden''s most distinctive structures, ingeniously combining four architectural forms into a single composition: a stone-paved platform at the bow, a covered corridor as the cabin, and a two-story tower at the stern — creating the illusion of an ornate pleasure boat moored by the water. The name "Fragrant Isle" evokes a lush, grassy islet. A plaque inscribed by the Ming master Wen Zhengming hangs at the bow, while the upper level, named "Chengguan Tower" (Tower of Clear Contemplation), offers sweeping views across shimmering garden waters. This is a quintessential example of the "dry boat" motif in classical Chinese gardens, brilliantly merging water-town imagery with garden architecture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_03.jpg', 2),
  ('suzhou_humble_administrators_garden_sa_04', 'suzhou_humble_administrators_garden', 'Hefeng Simian Pavilion (Lotus Breeze from All Sides Pavilion)', '荷风四面亭', '，，。""，。，，，，。"，"，。，，、、。 / Hefeng Simian Pavilion is a delicate hexagonal pavilion with a pointed roof, built on a rocky islet at the center of the garden''s main pond and connected to both shores by winding bridges. Its name, borrowed from Tang poet Meng Haoran''s line "the lotus breeze bears its fragrance," perfectly captures its poetic essence. In midsummer, when lotus blooms carpet the surrounding water and a gentle breeze carries their scent from all four sides, one feels as though standing inside a painting. The couplet on its pillars — "Lotus blossoms on four sides, willows on three; half a pool of autumn water, a mountain in one room" — elegantly evokes the changing seasons. Beyond being an exquisite lotus-viewing perch, this pavilion is the compositional linchpin of the garden''s waterscape, skillfully linking Yuanxiang Hall, Xiangzhou, and Jianshan Tower.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_04.jpg', 3),
  ('suzhou_humble_administrators_garden_sa_05', 'suzhou_humble_administrators_garden', 'Xiaofeihong (Little Flying Rainbow)', '小飞虹', '，。，，，。""，。，，，，。，，、、，""""。 / Xiaofeihong is a supremely poetic covered bridge and the only surviving example of its kind among Suzhou''s classical gardens. The three-span bridge features vermilion balustrades beneath a full-length roof, with green water flowing gently beneath. Its name, drawn from Bao Zhao''s verse "a flying rainbow gazes upon the Qin River," likens the bridge''s graceful arc to a rainbow. Connecting Yiyu Pavilion on one end to Dezhi Pavilion on the other, the bridge casts its reflection onto the water, blurring the line between reality and illusion. Viewed from Yuanxiang Hall, Xiaofeihong appears as a crimson arc suspended above the water, forming a richly layered composition with the pavilions, rockeries, and foliage beyond — a brilliant demonstration of "borrowed" and "divided" scenic techniques.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_05.jpg', 4),
  ('suzhou_humble_administrators_garden_sa_06', 'suzhou_humble_administrators_garden', 'Jianshan Tower (Tower of Seeing the Mountain)', '见山楼', '，，。"，"，、。，；，，，""——，。，。 / Jianshan Tower is the tallest structure in the garden, a two-story double-eaved building with a hip-and-gable roof standing on the northern shore of the garden''s main pond. Its name echoes Tao Yuanming''s famous lines "Picking chrysanthemums by the eastern hedge, I gaze in leisure upon the southern mountain," expressing the owner''s longing for a life of reclusion amid nature. The open-sided ground floor serves as a cool hall for watching fish and lotus, while the upper study commands a view that frames Suzhou''s iconic North Temple Pagoda — the supreme achievement of the Chinese garden technique of "borrowed scenery," pulling a city landmark into the garden''s visual field and vastly expanding its perceived depth. The waterfront terrace in front is one of the best spots for panoramic photography.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_06.jpg', 5),
  ('suzhou_humble_administrators_garden_sa_07', 'suzhou_humble_administrators_garden', 'Sanshiliu Yuanyang Guan (Thirty-Six Mandarin Duck Hall)', '卅六鸳鸯馆', '，""，。——，（），（），。，，，。、，。 / Sanshiliu Yuanyang Guan is the principal building of the garden''s western section, originally named for the thirty-six pairs of mandarin ducks that once graced the pond before it. The hall follows the "mandarin duck hall" layout — two halls separated by a screen partition: the southern hall is warm in winter with abundant sunlight, while the northern hall stays cool in summer with cross-ventilation from the water, a brilliant demonstration of traditional architectural wisdom. Its most striking feature is the stained-glass lattice windows on all four sides — blue-and-white diamond-patterned panes that refract dreamlike light and shadow, a rarity in classical Chinese gardens and a precious trace of Western influence during the late Qing period. The owner Zhang Luqian once entertained guests and enjoyed Kunqu opera here, and the hall''s exquisite wood carvings, plaques, and couplets still whisper of literati refinement.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_07.jpg', 6),
  ('suzhou_humble_administrators_garden_sa_08', 'suzhou_humble_administrators_garden', 'Yushei Tongzuo Pavilion (With Whom Shall I Sit Pavilion)', '与谁同坐轩', '，——、、、、，。"？"，、。，，，，，。，，""。 / Yushei Tongzuo Pavilion is one of the garden''s most inventive architectural designs: the pavilion is fan-shaped in plan — its roof, walls, doors, windows, stone table, stone stools, and even the hanging plaque are all in the form of a fan, an exquisite conceit. Its name comes from Su Shi''s celebrated verse "With whom shall I sit? The bright moon, the fresh breeze, and me" — a rhetorical question that conveys a transcendent detachment, a communion with the universe in splendid solitude. Perched at the southeastern corner of the western pond, with water on three sides and a covered corridor at its back, it faces Sanshiliu Yuanyang Guan across the water. This tiny fan-shaped space holds infinite poetry and philosophy, a perfect distillation of the classical Chinese garden aesthetic of "seeing the great in the small."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_08.jpg', 7),
  ('suzhou_humble_administrators_garden_sa_09', 'suzhou_humble_administrators_garden', 'Liuting Ge (Pavilion for Lingering and Listening)', '留听阁', '，，，。《》""，。，、，，、——""。，，，，、。，。 / Liuting Ge is a small, elegantly understated waterside pavilion in the garden''s western section — a single-story structure with a hip-and-gable roof, surrounded by water on three sides in serene seclusion. Its name is taken from the late Tang poet Li Shangyin''s haunting line "Leave the withered lotus to listen to the sound of rain," a verse suffused with melancholy and depth. In autumn, when the lotus blooms have faded and only withered stalks remain, the patter of rain on dry lotus leaves creates a rustling, intimate music — a celebration of imperfect, quiet beauty that represents the highest expression of the traditional Chinese aesthetic of wabi-like poignancy. Leaning on the railing, one gazes upon clear pond waters, a distant pagoda silhouette, and nearby withered lotus whispering in the rain — a moment of transcendence where time dissolves and the self merges with the scene. Liuting Ge is not merely a viewpoint; it is a state of mind.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/suzhou_humble_administrators_garden_sa_09.jpg', 8)
